    {
        var result = RunAcceptedExample(
            "deepseek:05265_39cc04782639a54c:cfdf12326db2cf40",
            """
            * Sallen-Key Chebyshev LP, 1dB ripple, fc~1kHz, -3dB at 1kHz
            VIN in 0 AC 1 DC 0
            R1 in va 10k
            R2 va inp 10k
