            .MODEL NPN NPN(IS=1e-15 BF=100 VAF=50)
            .OP
            .DC VOUT 0 5 0.1
            .MEAS DC Iout FIND I(Vmeas) AT=2.5
            .MEAS DC Iref FIND I(IREF) AT=2.5
