    // Prompt: 3-bit flash ADC with resistor ladder generating reference voltages at 0.3125V, 0.9375V, 1.5625V, 2.1875V, 2.8125V, 3.4375V, 4.0625V.
    [Fact]
    public void _3_bit_Flash_ADC_with_Resistor_Ladder_and_Ideal_Comparators_5a9d729265f9a713()
    {
        var result = RunAcceptedExample(
            "deepseek:07539_c561975c8c047148:5a9d729265f9a713",
            """
            * 3-bit Flash ADC with Resistor Ladder and Ideal Comparators
            VREF ref 0 DC 5
            VIN in 0 DC 0
            R1 ref t7 3k
            R2 t7 t6 2k
            R3 t6 t5 2k
            R4 t5 t4 2k
            R5 t4 t3 2k
            R6 t3 t2 2k
            R7 t2 t1 2k
            R8 t1 0 1k
            E1 out1 0 VALUE = { 5 * u(V(in) - V(t1)) }
            E2 out2 0 VALUE = { 5 * u(V(in) - V(t2)) }
            E3 out3 0 VALUE = { 5 * u(V(in) - V(t3)) }
            E4 out4 0 VALUE = { 5 * u(V(in) - V(t4)) }
            E5 out5 0 VALUE = { 5 * u(V(in) - V(t5)) }
            E6 out6 0 VALUE = { 5 * u(V(in) - V(t6)) }
            E7 out7 0 VALUE = { 5 * u(V(in) - V(t7)) }
            .DC VIN 0 5 0.01
            .MEAS DC out1_low FIND V(out1) AT=0.2
            .MEAS DC out1_high FIND V(out1) AT=0.4
            .MEAS DC out2_low FIND V(out2) AT=0.8
            .MEAS DC out2_high FIND V(out2) AT=1.1
            .MEAS DC out3_low FIND V(out3) AT=1.4
            .MEAS DC out3_high FIND V(out3) AT=1.7
            .MEAS DC out4_low FIND V(out4) AT=2.0
            .MEAS DC out4_high FIND V(out4) AT=2.4
            .MEAS DC out5_low FIND V(out5) AT=2.6
            .MEAS DC out5_high FIND V(out5) AT=3.0
            .MEAS DC out6_low FIND V(out6) AT=3.2
            .MEAS DC out6_high FIND V(out6) AT=3.6
            .MEAS DC out7_low FIND V(out7) AT=3.8
            .MEAS DC out7_high FIND V(out7) AT=4.2
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementLess(result, "out1_low", 1.0);
        AssertMeasurementGreater(result, "out1_high", 4.0);
        AssertMeasurementLess(result, "out2_low", 1.0);
        AssertMeasurementGreater(result, "out2_high", 4.0);
        AssertMeasurementLess(result, "out3_low", 1.0);
        AssertMeasurementGreater(result, "out3_high", 4.0);
        AssertMeasurementLess(result, "out4_low", 1.0);
        AssertMeasurementGreater(result, "out4_high", 4.0);
        AssertMeasurementLess(result, "out5_low", 1.0);
        AssertMeasurementGreater(result, "out5_high", 4.0);
        AssertMeasurementLess(result, "out6_low", 1.0);
        AssertMeasurementGreater(result, "out6_high", 4.0);
        AssertMeasurementLess(result, "out7_low", 1.0);
        AssertMeasurementGreater(result, "out7_high", 4.0);
    }

