    // Prompt: 3-bit flash ADC with 7 comparators and intentional input-referred offsets ranging from -5mV to +5mV.
    [Fact]
    public void _3_bit_Flash_ADC_with_Comparator_Offsets_Sorted_Thresholds_467636b9477337f3()
    {
        var result = RunAcceptedExample(
            "deepseek:07540_ad35c56dd2037069:467636b9477337f3",
            """
            * 3-bit Flash ADC with Comparator Offsets - Sorted Thresholds
            VREF ref 0 DC 5
            VIN in 0 DC 0
            R1 ref t1 2k
            R2 t1 t2 2k
            R3 t2 t3 2k
            R4 t3 t4 2k
            R5 t4 t5 2k
            R6 t5 t6 2k
            R7 t6 t7 2k
            R8 t7 0 2k
            * Offsets reordered so out1 is lowest threshold, out7 is highest
            VOS1 in1 in DC -2mV
            VOS2 in2 in DC 4mV
            VOS3 in3 in DC -4mV
            VOS4 in4 in DC 3mV
            VOS5 in5 in DC -3mV
            VOS6 in6 in DC 5mV
            VOS7 in7 in DC -5mV
            * Comparators: in+ shifted by offset, in- connected to ladder taps
            E1 out1 0 VALUE = { V(in1) > V(t7) ? 5 : 0 }
            E2 out2 0 VALUE = { V(in2) > V(t6) ? 5 : 0 }
            E3 out3 0 VALUE = { V(in3) > V(t5) ? 5 : 0 }
            E4 out4 0 VALUE = { V(in4) > V(t4) ? 5 : 0 }
            E5 out5 0 VALUE = { V(in5) > V(t3) ? 5 : 0 }
            E6 out6 0 VALUE = { V(in6) > V(t2) ? 5 : 0 }
            E7 out7 0 VALUE = { V(in7) > V(t1) ? 5 : 0 }
            .DC VIN 0 5 0.005
            .MEAS DC Vth1 FIND V(in) WHEN V(out1)=2.5
            .MEAS DC Vth2 FIND V(in) WHEN V(out2)=2.5
            .MEAS DC Vth3 FIND V(in) WHEN V(out3)=2.5
            .MEAS DC Vth4 FIND V(in) WHEN V(out4)=2.5
            .MEAS DC Vth5 FIND V(in) WHEN V(out5)=2.5
            .MEAS DC Vth6 FIND V(in) WHEN V(out6)=2.5
            .MEAS DC Vth7 FIND V(in) WHEN V(out7)=2.5
            .MEAS DC LSB PARAM = 5/8
            .MEAS DC DNL1 PARAM = (Vth1-0)/LSB - 1
            .MEAS DC DNL2 PARAM = (Vth2-Vth1)/LSB - 1
            .MEAS DC DNL3 PARAM = (Vth3-Vth2)/LSB - 1
            .MEAS DC DNL4 PARAM = (Vth4-Vth3)/LSB - 1
            .MEAS DC DNL5 PARAM = (Vth5-Vth4)/LSB - 1
            .MEAS DC DNL6 PARAM = (Vth6-Vth5)/LSB - 1
            .MEAS DC DNL7 PARAM = (Vth7-Vth6)/LSB - 1
            .MEAS DC DNL8 PARAM = (5 - Vth7)/LSB - 1
            .MEAS DC INL1 PARAM = (Vth1 - 1*LSB)/LSB
            .MEAS DC INL2 PARAM = (Vth2 - 2*LSB)/LSB
            .MEAS DC INL3 PARAM = (Vth3 - 3*LSB)/LSB
            .MEAS DC INL4 PARAM = (Vth4 - 4*LSB)/LSB
            .MEAS DC INL5 PARAM = (Vth5 - 5*LSB)/LSB
            .MEAS DC INL6 PARAM = (Vth6 - 6*LSB)/LSB
            .MEAS DC INL7 PARAM = (Vth7 - 7*LSB)/LSB
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var dnl_names = new[] { "DNL1", "DNL2", "DNL3", "DNL4", "DNL5", "DNL6", "DNL7", "DNL8" };
        var inl_names = new[] { "INL1", "INL2", "INL3", "INL4", "INL5", "INL6", "INL7" };
        foreach (var name in dnl_names.Concat(inl_names))
        {
            AssertMeasurementBetween(result, name, (-0.02), 0.02);
        }
    }

