            .DC VIN 0 3.3 0.005
            .MEAS DC out1_0_2 FIND V(out1) AT=0.2
            .MEAS DC out2_0_2 FIND V(out2) AT=0.2
            .MEAS DC out3_0_2 FIND V(out3) AT=0.2
            .MEAS DC out4_0_2 FIND V(out4) AT=0.2
            .MEAS DC out5_0_2 FIND V(out5) AT=0.2
            .MEAS DC out6_0_2 FIND V(out6) AT=0.2
            .MEAS DC out7_0_2 FIND V(out7) AT=0.2
            .MEAS DC out1_1_0 FIND V(out1) AT=1.0
            .MEAS DC out2_1_0 FIND V(out2) AT=1.0
            .MEAS DC out3_1_0 FIND V(out3) AT=1.0
            .MEAS DC out4_1_0 FIND V(out4) AT=1.0
            .MEAS DC out5_1_0 FIND V(out5) AT=1.0
            .MEAS DC out6_1_0 FIND V(out6) AT=1.0
            .MEAS DC out7_1_0 FIND V(out7) AT=1.0
            .MEAS DC out1_2_0 FIND V(out1) AT=2.0
            .MEAS DC out2_2_0 FIND V(out2) AT=2.0
            .MEAS DC out3_2_0 FIND V(out3) AT=2.0
            .MEAS DC out4_2_0 FIND V(out4) AT=2.0
            .MEAS DC out5_2_0 FIND V(out5) AT=2.0
            .MEAS DC out6_2_0 FIND V(out6) AT=2.0
            .MEAS DC out7_2_0 FIND V(out7) AT=2.0
            .MEAS DC out1_3_0 FIND V(out1) AT=3.0
            .MEAS DC out2_3_0 FIND V(out2) AT=3.0
            .MEAS DC out3_3_0 FIND V(out3) AT=3.0
            .MEAS DC out4_3_0 FIND V(out4) AT=3.0
            .MEAS DC out5_3_0 FIND V(out5) AT=3.0
            .MEAS DC out6_3_0 FIND V(out6) AT=3.0
            .MEAS DC out7_3_0 FIND V(out7) AT=3.0
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        foreach (var name in new[] { "out1_0_2", "out2_0_2", "out3_0_2", "out4_0_2", "out5_0_2", "out6_0_2", "out7_0_2" })
        {
            AssertMeasurementLess(result, name, 0.5);
        }
        foreach (var name in new[] { "out1_1_0", "out2_1_0", "out3_1_0", "out4_1_0", "out5_1_0" })
        {
            AssertMeasurementLess(result, name, 0.5);
        }
        foreach (var name in new[] { "out6_1_0", "out7_1_0" })
        {
            AssertMeasurementGreater(result, name, 2.8);
        }
        foreach (var name in new[] { "out1_2_0", "out2_2_0", "out3_2_0" })
        {
            AssertMeasurementLess(result, name, 0.5);
        }
        foreach (var name in new[] { "out4_2_0", "out5_2_0", "out6_2_0", "out7_2_0" })
        {
            AssertMeasurementGreater(result, name, 2.8);
        }
        foreach (var name in new[] { "out1_3_0", "out2_3_0", "out3_3_0", "out4_3_0", "out5_3_0", "out6_3_0", "out7_3_0" })
        {
            AssertMeasurementGreater(result, name, 2.8);
        }
    }

