            C1 cap 0 1u
            R1 cap 0 100k
            E2 out 0 cap out 100k
            VCTRL ctrl 0 PULSE(0 5 0 1u 1u 5m 10m)
            .TRAN 1u 15m 0 1u
            .MEAS TRAN max_vout MAX V(out) FROM=0 TO=5m
            .MEAS TRAN hold_start_vout FIND V(out) AT=5.1m
            .MEAS TRAN hold_end_vout FIND V(out) AT=9.9m
            .MEAS TRAN droop PARAM = (hold_start_vout - hold_end_vout)
            .MEAS TRAN droop_mv PARAM = (droop*1000)
