    // Prompt: The netlist implements a 555-style monostable timer using behavioral comparators, an SR latch, a switch, and RC timing.
    [Fact]
    public void _555_style_monostable_timer_using_behavioral_comparators_e361f53e5a7978ce()
    {
        var result = RunAcceptedExample(
            "deepseek:01816_617489d68d062795:e361f53e5a7978ce",
            """
            * 555-style monostable timer using behavioral comparators
            VCC vcc 0 DC 5
            * Trigger pulse: normally high, negative pulse at 5ms
            VTRIG trigger 0 PULSE(5 0 5m 10n 10n 100u 20m)
            * Timing resistor and capacitor
            R1 vcc cap 10k
            C1 cap 0 1u IC=0
            * Behavioral comparators
            E_set set 0 VALUE = { V(trigger) < V(vcc)/3 ? 5 : 0 }
            E_reset reset 0 VALUE = { V(cap) > 2*V(vcc)/3 ? 5 : 0 }
            * SR latch using cross-coupled NOR gates
            .SUBCKT NOR2 a b out
            E1 out 0 VALUE = { (V(a) > 2.5 || V(b) > 2.5) ? 0 : 5 }
            .ENDS
            X1 reset qbar q NOR2
            X2 set q qbar NOR2
            .IC V(q)=0 V(qbar)=5
            * Discharge switch
            .MODEL SW SW(RON=10 ROFF=10MEG VT=2.5 VH=0)
            S1 cap 0 qbar 0 SW
            * Output buffer
            E_out out 0 q 0 1
            * Analysis
            .TRAN 1u 50m
            * Measurements
            .MEAS TRAN pulse_width TRIG V(out) VAL=2.5 RISE=1 TARG V(out) VAL=2.5 FALL=1
            .MEAS TRAN vout_max MAX V(out)
            .MEAS TRAN vout_min MIN V(out)
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "pulse_width", 0.01, 0.012);
        AssertMeasurementNear(result, "vout_max", 5.0, 0.1);
        AssertMeasurementNear(result, "vout_min", 0.0, 0.1);
    }

