            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var vout0 = MeasurementValue(result, "VOUT0");
        var vout1 = MeasurementValue(result, "VOUT1");
        Assert.True(((3.5 < vout0) && (vout0 < 4.5)), CaseLabel(result));
        Assert.True(((3.2 < vout1) && (vout1 < 4.3)), CaseLabel(result));
        var diff = (vout1 - vout0);
