    // Prompt: A 555-style monostable multivibrator built from behavioral voltage sources and an RC network.
    [Fact]
    public void _555_style_monostable_timer_using_behavioral_comparators_with_NAND_latch_15fd6279e0a26955()
    {
        var result = RunAcceptedExample(
            "deepseek:01817_a766f76f5ab0e98e:15fd6279e0a26955",
            """
            * 555-style monostable timer using behavioral comparators with NAND latch
            VCC VCC 0 DC 5
            VTRIG trig 0 PULSE(5 0 1m 10n 10n 100u 50m)
            R1 VCC th 10k
            C1 th 0 1u
            E_TRIG set 0 VALUE = { IF(V(trig) < 5/3, 0, 5) }
            E_THRESH reset 0 VALUE = { IF(V(th) > 10/3, 0, 5) }
            E_LATCH_Q q 0 VALUE = { IF(V(set)>2.5, IF(V(_q)>2.5, 0, 5), 5) }
            E_LATCH_NQ _q 0 VALUE = { IF(V(reset)>2.5, IF(V(q)>2.5, 0, 5), 5) }
            R_Q q 0 1G
            R_NQ _q 0 1G
            C_Q q 0 10p
            C_NQ _q 0 10p
            .IC V(q)=0 V(_q)=5
            E_DISCH_CTRL dctrl 0 VALUE = { IF(V(q)>2.5, 0, 5) }
            S_DISCH th 0 dctrl 0 SW
            .MODEL SW SW(RON=10 ROFF=10MEG VT=0.5)
            E_OUT out 0 VALUE = { V(q) }
            .TRAN 10u 50m
            .MEAS TRAN pulse_width TRIG V(out) VAL=2.5 RISE=1 TARG V(out) VAL=2.5 FALL=1
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "pulse_width", 0.011, 0.001);
    }

