    // Prompt: BJT translinear four-quadrant multiplier based on a Gilbert cell.
    [Fact]
    public void BJT_Translinear_Four_Quadrant_Multiplier_Gilbert_Cell_a9653186ebcb1eed()
    {
        var result = RunAcceptedExample(
            "deepseek:02398_2da23d642de94428:a9653186ebcb1eed",
            """
            * BJT Translinear Four-Quadrant Multiplier (Gilbert Cell)
            VCC VCC 0 DC 10
            VEE VEE 0 DC -10
            * Input VX: differential with 2V common mode and 10mV peak each side, 1kHz
            VX1 xp 0 SINE(2 0.01 1k)
            VX2 xm 0 SINE(2 -0.01 1k)
            * Input VY: differential with 0V common mode and 10mV peak each side, 10kHz
            VY1 yp 0 SINE(0 0.01 10k)
            VY2 ym 0 SINE(0 -0.01 10k)
            * Tail current source
            I_TAIL N001 VEE 1m
            * Differential pair for Y: Q5 and Q6
            Q5 N002 yp N001 npnmod
            Q6 N003 ym N001 npnmod
            * Multiplier core: Q1-Q4
            Q1 A xp N002 npnmod
            Q2 B xm N002 npnmod
            Q3 A xm N003 npnmod
            Q4 B xp N003 npnmod
            * Load resistors
            R1 A VCC 10k
            R2 B VCC 10k
            * Output differential-to-single-ended converter (gain=1)
            E1 out 0 VALUE={V(A)-V(B)}
            * Measurement dummy load
            Rout out 0 100k
            * Models
            .MODEL npnmod NPN(IS=1e-15 BF=100)
            * Analysis: transient for 10ms with maximum timestep 10us
            .TRAN 10us 10ms 0ms 10us
            * Measurements
            .MEAS TRAN vout_rms RMS V(out) FROM=1ms TO=10ms
            .MEAS TRAN vout_pp PP V(out) FROM=1ms TO=10ms
            .MEAS TRAN vout_avg AVG V(out) FROM=1ms TO=10ms
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "vout_rms", 0.5, 1.0);
        AssertMeasurementBetween(result, "vout_pp", 2.0, 4.0);
        AssertMeasurementNear(result, "vout_avg", 0.0, 0.1);
    }

    // Prompt: Create a SPICE netlist of an active peak detector circuit. Use a behavioral op-amp (E source) with a diode in the feedback path to charge a capacitor to the peak input voltage. Include a buffer op-amp to read the capacitor voltage. Design a piecewise linear input waveform with multiple peaks and a reset pulse to discharge the holding capacitor. Perform a transient analysis and add .MEAS statements to verify the peak holding and reset behavior.
