            "deepseek:00427_2aa5eefe9796f500:c78730346598d2b2",
            """
            * Monostable multivibrator using RC and comparator
            .OPTIONS RELTOL=1e-4
            VCC vcc 0 DC 5
            VREF ref 0 DC 2.5
            VTRIG trigger 0 PULSE(0 5 200u 10n 10n 10u 1m)
            Rf out in_plus 100k
            R1 in_plus ref 100k
            Rtim out in_minus 10k
            Rpullup vcc in_minus 10k
            Ctim in_minus 0 50nF
            S1 in_minus 0 trigger 0 SWMOD
