            EOP out 0 VALUE={min(5, max(0, 1e5*(V(in_plus, in_minus))))}
            .TRAN 0.01u 2m
            .MEAS TRAN trig_rise WHEN V(trigger)=2.5 RISE=1
            .MEAS TRAN pulse_width TRIG V(trigger) VAL=2.5 RISE=1 TARG V(out) VAL=2.5 FALL=1
            .MEAS TRAN v_cap_low FIND V(in_minus) AT=199u
            .MEAS TRAN vout_max MAX V(out) FROM=0 TO=2m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
