    public void CDS_Front_End_with_Offset_Cancellation_ef70048d11607a22()
    {
        var result = RunAcceptedExample(
            "deepseek:02277_9bcdbdbb0b0c37d1:ef70048d11607a22",
            """
            * CDS Front End with Offset Cancellation
            VIN in 0 PULSE(0.2 0.8 5u 10n 10n 4u 10u)
            VPHI1 phi1 0 PULSE(0 5 0 10n 10n 5u 10u)
            Cc in cright 1u
