            E1 out_int 0 cright 0 1
            Voff out out_int DC 0.01
            Rload out 0 10k
            .MODEL swmod SW(RON=10 ROFF=100MEG VT=2 VH=0.5)
            .TRAN 0.1u 10u
            .MEAS TRAN vout_clamp FIND V(out) AT=4us
            .MEAS TRAN vout_sig FIND V(out) AT=8us
