            .IC V(vctrl)=1.5 V(vfilt)=1.5
            * Transient analysis
            .TRAN 0.1u 50u UIC
            * Measurements
            .MEAS TRAN v_avg AVG V(vctrl) FROM=20u TO=50u
            .MEAS TRAN v_pp PP V(vctrl) FROM=20u TO=50u
            .MEAS TRAN v_max MAX V(vctrl) FROM=10u TO=50u
            .MEAS TRAN v_min MIN V(vctrl) FROM=10u TO=50u
            .END
            """);

