            .ac dec 10 1 100meg
            .meas dc vout_p find v(out_p) when v(inp)=2.5
            .meas dc vout_n find v(out_n) when v(inp)=2.5
            .meas dc vos param='vout_p - vout_n'
            .meas ac gain_lf find vdb(out_p) at=1
            .meas ac gain_hf find vdb(out_p) at=100k
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var vos = MeasurementValue(result, "vos");
        Assert.True(((Math.Abs(vos) < 0.001)), CaseLabel(result));
        var gain_lf = MeasurementValue(result, "gain_lf");
        Assert.True(((9.0 < gain_lf) && (gain_lf < 14.0)), CaseLabel(result));
        var gain_hf = MeasurementValue(result, "gain_hf");
        Assert.True(((gain_hf > 8.0)), CaseLabel(result));
    }

