    public void Sample_and_hold_front_end_with_clocked_switch_9dcd80f790405baa()
    {
        var result = RunAcceptedExample(
            "deepseek:02239_fc4680923c537154:9dcd80f790405baa",
            """
            * Sample-and-hold front end with clocked switch
            .MODEL swmod SW(RON=1 ROFF=10MEG VT=2.5 VH=0.5)
            .tran 1u 2m
            VIN in 0 SIN(2 1 500)
            VCLK clk 0 PULSE(0 5 0 10n 10n 200u 500u)
            S1 in cap clk 0 swmod
            C1 cap 0 100n
            E_buf out 0 cap 0 1
            Rload out 0 10MEG
            .measure tran v_hold_start find V(out) AT=300u
            .measure tran v_hold_end   find V(out) AT=450u
            .measure tran v_track find V(out) AT=100u
            .measure tran v_in_track find V(in) AT=100u
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var measures = MeasurementsDictionary(result);
        var v_hold_start = measures["v_hold_start"];
        var v_hold_end = measures["v_hold_end"];
        var droop = Math.Abs((v_hold_start - v_hold_end));
        Assert.True(((droop < 0.01)), CaseLabel(result));
        var v_track = measures["v_track"];
        var v_in_track = measures["v_in_track"];
        var track_err = Math.Abs((v_track - v_in_track));
        Assert.True(((track_err < 0.01)), CaseLabel(result));
    }

