    // Prompt: Design an emitter-coupled logic (ECL) differential switch using BJTs. Apply a PULSE input and a DC reference voltage. Run DC operating point and transient analysis. Measure output voltages to verify differential switching behavior.
    [Fact]
    public void Emitter_Coupled_Logic_Differential_Switch_5c521ad9fd32d343()
    {
        var result = RunAcceptedExample(
            "deepseek:01180_b6e31f3679ec932c:5c521ad9fd32d343",
            """
            * Emitter-Coupled Logic Differential Switch
            VCC vcc 0 DC 5
            VEE vee 0 DC -5
            I1 emitter vee DC 1m
            Q1 out1 in emitter 0 qn
            Q2 out2 vref emitter 0 qn
            R1 vcc out1 1k
            R2 vcc out2 1k
            Vref vref 0 DC -0.5
            VIN in 0 PULSE(-1 0 50n 1n 1n 50n 200n)
            .MODEL qn NPN(IS=1e-15 BF=100)
            .OP
            .TRAN 1n 200n
            .MEAS TRAN vout1_l AVG V(out1) FROM=10n TO=40n
            .MEAS TRAN vout1_h AVG V(out1) FROM=60n TO=90n
            .MEAS TRAN vout2_l AVG V(out2) FROM=10n TO=40n
            .MEAS TRAN vout2_h AVG V(out2) FROM=60n TO=90n
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var v1l = MeasurementValue(result, "vout1_l");
        var v1h = MeasurementValue(result, "vout1_h");
        var v2l = MeasurementValue(result, "vout2_l");
        var v2h = MeasurementValue(result, "vout2_h");
        Assert.True(((v1l > v1h)), CaseLabel(result));
        Assert.True(((v2h > v2l)), CaseLabel(result));
    }

