            .MEAS TRAN Vheld FIND V(out) AT=0.95m
            .MEAS TRAN Vhold_end FIND V(out) AT=2.95m
            .MEAS TRAN Verror PARAM '100*abs(Vheld-Vsample)/(abs(Vsample)+1p)'
            .MEAS TRAN Vdroop PARAM 'Vheld - Vhold_end'
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "Vsample", (-0.5878), 0.01);
        AssertMeasurementNear(result, "Vheld", (-0.5878), 0.01);
        AssertMeasurementLess(result, "Verror", 0.1);
        AssertMeasurementBetween(result, "Vdroop", (-0.013), (-0.01));
    }

