    {
        var result = RunAcceptedExample(
            "deepseek:02206_200d811a6ef6f3d4:6aeae66620c1ecda",
            """
            * 3-bit Flash ADC with resistor ladder and comparator bank
            Vcc vcc 0 DC 5
            Vref vref 0 DC 5
            Vin in 0 DC 0 PULSE(0 5 0 1m 1m 2m 5m)
            
            * Input buffer (E-source voltage follower, gain=1)
            E_buf buf 0 in 0 1
            
            * Resistor ladder: 8 equal resistors from vref to ground
            R1 vref n1 1k
            R2 n1 n2 1k
            R3 n2 n3 1k
            R4 n3 n4 1k
            R5 n4 n5 1k
            R6 n5 n6 1k
            R7 n6 n7 1k
            R8 n7 0 1k
            
            * Comparator bank using voltage-controlled switches with pull-up resistors
            .model SWMOD SW(RON=1 ROFF=100MEG VT=0 VH=0)
            S7 vcc out7 buf n7 SWMOD
            S6 vcc out6 buf n6 SWMOD
            S5 vcc out5 buf n5 SWMOD
            S4 vcc out4 buf n4 SWMOD
            S3 vcc out3 buf n3 SWMOD
            S2 vcc out2 buf n2 SWMOD
            S1 vcc out1 buf n1 SWMOD
            
            Rup7 out7 0 10k
            Rup6 out6 0 10k
            Rup5 out5 0 10k
            Rup4 out4 0 10k
            Rup3 out3 0 10k
            Rup2 out2 0 10k
            Rup1 out1 0 10k
            
            * Analyses
            .DC Vin 0 5 0.01
            .TRAN 1u 10m
            
            * Measurements
            .MEAS DC vth7 WHEN V(out7)=2.5
            .MEAS DC vth6 WHEN V(out6)=2.5
            .MEAS DC vth5 WHEN V(out5)=2.5
            .MEAS DC vth4 WHEN V(out4)=2.5
            .MEAS DC vth3 WHEN V(out3)=2.5
            .MEAS DC vth2 WHEN V(out2)=2.5
            .MEAS DC vth1 WHEN V(out1)=2.5
            
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "vth7", 0.625, 0.05);
        AssertMeasurementNear(result, "vth6", 1.25, 0.05);
        AssertMeasurementNear(result, "vth5", 1.875, 0.05);
        AssertMeasurementNear(result, "vth4", 2.5, 0.05);
        AssertMeasurementNear(result, "vth3", 3.125, 0.05);
        AssertMeasurementNear(result, "vth2", 3.75, 0.05);
        AssertMeasurementNear(result, "vth1", 4.375, 0.05);
    }

