    // Prompt: Switching preregulator (buck converter) steps 12V down to ~4.8V using a fixed 40% duty cycle at 100kHz.
    [Fact]
    public void Linear_Post_Regulator_After_Switching_Preregulator_7cbc98f5869d8e9e()
    {
        var result = RunAcceptedExample(
            "deepseek:02004_2abb4e9469bbfb96:7cbc98f5869d8e9e",
            """
            * Linear Post-Regulator After Switching Preregulator
            VIN in 0 DC 12
            VPULSE ctrl 0 PULSE(0 5 0 10n 10n 4u 10u)
            S1 in sw ctrl 0 SWMOD
            D1 0 sw DDIODE
            L1 sw vsw 100u
            C1 vsw 0 100u
            Rsw vsw 0 100
            VREF ref 0 DC 1.25
            R1 out fb 16.4k
            R2 fb 0 10k
            Eamp eout 0 fb ref 100k
            Cc eout fb 100p
            Rb eout qb 1
            Q1 vsw qb out QNPN
            Cout out 0 10u
            ILOAD out 0 PULSE(0.05 0.5 2m 1u 1u 2m 10m)
            .MODEL QNPN NPN(IS=1e-14 BF=200)
            .MODEL DDIODE D(IS=1n RS=0.1)
            .MODEL SWMOD SW(RON=0.1 ROFF=1MEG VT=2.5 VH=0.1)
            .OP
            .TRAN 1u 10m
            .MEAS TRAN vout_low AVG V(out) FROM=1.5m TO=1.9m
            .MEAS TRAN vout_high AVG V(out) FROM=3m TO=3.5m
            .MEAS TRAN ripple PP V(out) FROM=1.5m TO=1.55m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var meas = MeasurementsDictionary(result);
        var vout_low = meas["vout_low"];
        var vout_high = meas["vout_high"];
        var ripple = meas["ripple"];
        Assert.True(((Math.Abs((vout_low - 3.3)) < 0.1)), CaseLabel(result));
        Assert.True(((Math.Abs((vout_high - 3.3)) < 0.1)), CaseLabel(result));
        Assert.True(((ripple < 0.05)), CaseLabel(result));
        var load_reg_pct = ((100.0 * (vout_low - vout_high)) / 3.3);
        Assert.True(((load_reg_pct < 5.0)), CaseLabel(result));
    }

