    {
        var result = RunAcceptedExample(
            "deepseek:01167_2a4864f294863e04:cf57d769a5840ea1",
            """
            * BJT Bistable Multivibrator Latch with SET/RESET
            VCC 1 0 DC 5
            Vset set 0 PULSE(0 5 10u 0.1u 0.1u 5u 100u)
            Vrst rst 0 PULSE(0 5 30u 0.1u 0.1u 5u 100u)
            Q1 out q1_base 0 npnmod
            Q2 outbar q2_base 0 npnmod
            Rc1 1 out 1k
            Rc2 1 outbar 1k
            R3 outbar q1_base 10k
            R4 out q2_base 10k
            R5 q1_base 0 10k
            R6 q2_base 0 9.1k
            Rset set_node set 1k
            Dset set_node q2_base Dmod
            Rsetpd set_node 0 10k
            Rrst rst_node rst 1k
            Drst rst_node q1_base Dmod
            Rrstpd rst_node 0 10k
            C1 out 0 10pF
            C2 outbar 0 10pF
            .MODEL npnmod NPN(IS=1e-15 BF=100 VAF=50)
            .MODEL Dmod D(IS=1e-14)
            .TRAN 0.1u 100u UIC
            .IC V(out)=0.2 V(outbar)=5
            .OPTIONS RELTOL=1e-3 ITL1=200
            .MEAS TRAN t_rise WHEN V(out)=2.5 TD=10u RISE=1
            .MEAS TRAN t_fall WHEN V(out)=2.5 TD=30u FALL=1
            .MEAS TRAN v_out_20u FIND V(out) AT=20u
            .MEAS TRAN v_out_40u FIND V(out) AT=40u
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
