            R7 n6 n7 1k
            R8 n7 0 1k
            E1 c1 0 VALUE { IF(V(in)-V(n1)>0, 5, 0) }
            E2 c2 0 VALUE { IF(V(in)-V(n2)>0, 5, 0) }
            E3 c3 0 VALUE { IF(V(in)-V(n3)>0, 5, 0) }
