            E7 c7 0 VALUE { IF(V(in)-V(n7)>0, 5, 0) }
            .DC VIN 0 5 0.01
            .TRAN 10n 10u 0 1n
            .MEAS DC v_th1 WHEN V(c1)=2.5 CROSS=1
            .MEAS DC v_th2 WHEN V(c2)=2.5 CROSS=1
            .MEAS DC v_th3 WHEN V(c3)=2.5 CROSS=1
