            .MEAS TRAN t_rise5 WHEN V(c5)=2.5 CROSS=1 TD=0
            .MEAS TRAN t_rise6 WHEN V(c6)=2.5 CROSS=1 TD=0
            .MEAS TRAN t_rise7 WHEN V(c7)=2.5 CROSS=1 TD=0
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
