    // Prompt: Added DC level shift of 1.5V to x inputs to prevent saturation of lower differential pair.
    [Fact]
    public void BJT_Gilbert_Multiplier_Core_with_proper_DC_biasing_02816b1cd66ee8d9()
    {
        var result = RunAcceptedExample(
            "deepseek:02282_22a8b5ea86d97959:02816b1cd66ee8d9",
            """
            * BJT Gilbert Multiplier Core with proper DC biasing
            Vcc vcc 0 DC 5
            Vee vee 0 DC -5
            * Vy differential input: yp=+10mV, ym=0V => Vy_diff=+10mV
            Vyp yp 0 DC 10m
            Vym ym 0 DC 0
            * Vx differential input with DC offset to avoid saturation of lower pair
            Vx_offset xp_int 0 DC 1.5
            Vxm xm 0 DC 1.5
            Vx_sweep xp xp_int DC 0
            * Load resistors
            R1 vcc out1 1k
            R2 vcc out2 1k
            * Upper quad (cross-coupled)
            Q1 out2 xp e1 npn
            Q2 out1 xm e1 npn
            Q3 out1 xp e2 npn
            Q4 out2 xm e2 npn
            * Lower differential pair
            Q5 e1 yp e3 npn
            Q6 e2 ym e3 npn
            * Tail current source 4mA
            Iee e3 vee 4m
            .MODEL npn NPN(IS=1e-15 BF=100)
            .OP
            .DC Vx_sweep -10m 10m 0.1m
            .MEAS DC vout_at_p10m FIND V(out1,out2) AT=10m
            .MEAS DC vout_at_m10m FIND V(out1,out2) AT=-10m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "vout_at_p10m", 0.148, 0.01);
        AssertMeasurementNear(result, "vout_at_m10m", (-0.148), 0.01);
    }

