    // Prompt: Three op-amp quadrature oscillator topology: two integrators and one inverter.
    [Fact]
    public void Quadrature_Oscillator_using_three_op_amps_E_sources_66072da47e641ae7()
    {
        var result = RunAcceptedExample(
            "deepseek:01748_bb41486784df12b7:66072da47e641ae7",
            """
            * Quadrature Oscillator using three op-amps (E sources)
            R1 out3 n1 10k
            C1 out1 n1 15.915n
            R2 out1 n2 10k
            C2 out2 n2 15.915n
            R3 out2 n3 10k
            R4 out3 n3 10k
            E1 out1 0 n1 0 1e6
            E2 out2 0 n2 0 1e6
            E3 out3 0 n3 0 1e6
            .ic V(n1)=0.1
            .tran 0.01m 5m uic
            .meas tran t_period trig v(out1) val=0 rise=1 targ v(out1) val=0 rise=2
            .meas tran t1 when v(out1)=0 rise=1
            .meas tran t2 when v(out2)=0 rise=1
            .meas tran vout1_pp PP v(out1) from=1m to=5m
            .end
            """);

        AssertAllMeasurementsSuccessful(result);
        var meas = MeasurementsDictionary(result);
        var period = meas["t_period"];
        var freq = (1.0 / period);
        Assert.True(((Math.Abs((freq - 1000.0)) < 50.0)), CaseLabel(result));
        var t1 = meas["t1"];
        var t2 = meas["t2"];
        var phase_diff = ((Math.Abs((t2 - t1)) * 360.0) / period);
        Assert.True(((85.0 < phase_diff) && (phase_diff < 95.0)), CaseLabel(result));
        var vpp = meas["vout1_pp"];
        Assert.True(((vpp > 0.1)), CaseLabel(result));
    }

