    // Prompt: 555-style monostable timer using behavioral comparators and SR latch
    [Fact]
    public void _555_style_monostable_timer_using_behavioral_comparators_4c7489ee15ac2c77()
    {
        var result = RunAcceptedExample(
            "deepseek:01821_48fa16fb32b123cc:4c7489ee15ac2c77",
            """
            * 555-style monostable timer using behavioral comparators
            VSUPPLY vcc 0 DC 5
            VTRIG trig 0 PULSE(5 0 10u 1n 1n 1u 200u)
            R1 vcc cap 100k
            C1 cap 0 10n
            R2 vcc ref_2_3 10k
            R3 ref_2_3 ref_1_3 10k
            R4 ref_1_3 0 10k
            E_SET SET 0 VALUE={5*(V(trig) < V(ref_1_3))}
            E_RESET RESET 0 VALUE={5*(V(cap) > V(ref_2_3))}
            E_nQ nQ 0 VALUE={5*((V(SET)<2.5)*(V(Q)<2.5))}
            E_Q Q 0 VALUE={5*((V(RESET)<2.5)*(V(nQ)<2.5))}
            .IC V(Q)=0 V(nQ)=5 V(cap)=0
            S_DISCH cap 0 nQ 0 SWMOD
            .MODEL SWMOD SW(RON=10 ROFF=10MEG VT=2.5 VH=0.5)
            E_OUT out 0 Q 0 1
            .TRAN 1u 2m UIC
            .MEAS TRAN pulse_width TRIG V(out) VAL=2.5 RISE=1 TD=0 TARG V(out) VAL=2.5 FALL=1
            .MEAS TRAN max_cap MAX V(cap)
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "pulse_width", 0.0011, 5e-05);
        AssertMeasurementNear(result, "max_cap", 3.333, 0.1);
    }

