    {
        var result = RunAcceptedExample(
            "deepseek:00093_ea190a23e5e96ba5:d5492ab73cc39ddc",
            """
            * Twin-T Notch Filter - AC Analysis
            V1 in 0 DC 0 AC 1
            R1 in n1 10k
            R2 n1 out 10k
            C1 n1 0 20n
            C2 in n2 10n
            C3 n2 out 10n
            R3 n2 0 7.5k
