    // Prompt: Boost converter with RCD snubber across MOSFET to limit switching voltage spikes.
    [Fact]
    public void Boost_Converter_with_RCD_Snubber_a5e8de5bbae70eac()
    {
        var result = RunAcceptedExample(
            "deepseek:01990_0bece25f58095e05:a5e8de5bbae70eac",
            """
            * Boost Converter with RCD Snubber
            VIN in 0 DC 12
            VG gate 0 PULSE(0 10 0 10n 10n 5.4u 10u)
            L1 in sw 100u
            M1 sw gate 0 0 nmos
            D1 sw out dmod
            C1 out 0 100u
            Rload out 0 10
            D2 sw snub_mid dmod
            Rsnub sw snub_mid 100
            Csnub snub_mid 0 10n
            .MODEL dmod D(IS=1e-12 RS=0.1 CJO=10p)
            .MODEL nmos NMOS(VTO=2 KP=1 LAMBDA=0.01)
            Bpwr pwr 0 V=V(out)*V(out)/10
            Bin in_pwr 0 V=-V(in)*I(VIN)
            .TRAN 0.1u 5m
            .MEAS TRAN Vout_avg AVG V(out) FROM=4m TO=5m
            .MEAS TRAN Pin_avg AVG V(in_pwr) FROM=4m TO=5m
            .MEAS TRAN Pout_avg AVG V(pwr) FROM=4m TO=5m
            .MEAS TRAN Eff PARAM='Pout_avg/Pin_avg'
            .MEAS TRAN Vds_max MAX V(sw) FROM=4m TO=5m
            .MEAS TRAN Vsnub_max MAX V(snub_mid) FROM=4m TO=5m
            .MEAS TRAN I_L_avg AVG I(L1) FROM=4m TO=5m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "Vout_avg", 23.0, 25.0);
        AssertMeasurementBetween(result, "Eff", 0.6, 0.95);
        AssertMeasurementLess(result, "Vds_max", 40.0);
        AssertMeasurementLess(result, "Vsnub_max", 40.0);
        AssertMeasurementGreater(result, "I_L_avg", 0.0);
    }

