    // Prompt: Monostable 555 timer implemented with behavioral comparators and a switched-capacitor latch.
    [Fact]
    public void _555_monostable_timer_using_behavioral_comparators_switched_capacitor_latch_and_discharge_switch_1daf9285cad40f05()
    {
        var result = RunAcceptedExample(
            "deepseek:01819_db0f353ed1e2dda8:1daf9285cad40f05",
            """
            * 555 monostable timer using behavioral comparators, switched-capacitor latch, and discharge switch
            VCC vcc 0 DC 5
            VTRIG trigger 0 PULSE(5 0 1m 1n 1n 0.1m 100m)
            R_DIV1 vcc v2 10k
            R_DIV2 v2 v1 10k
            R_DIV3 v1 0 10k
            R_TIM vcc thres 10k
            C_TIM thres 0 1uF IC=0
            E_TRIG_LOW trig_low 0 VALUE={ IF(V(trigger) < V(v1), 5, 0) }
            E_THRES_HIGH thres_high 0 VALUE={ IF(V(thres) > V(v2), 5, 0) }
            C_LATCH latch 0 100nF IC=0
            .MODEL SW_LATCH SW(RON=1k ROFF=10MEG VT=2.5 VH=0.5)
            S_SET vcc latch trig_low 0 SW_LATCH
            S_RESET latch 0 thres_high 0 SW_LATCH
            E_OUT out 0 VALUE={ IF(V(latch) > 2.5, 5, 0) }
            E_DIS dis_ctrl 0 VALUE={ IF(V(latch) < 2.5, 5, 0) }
            .MODEL SW_DIS SW(RON=10 ROFF=10MEG VT=2.5 VH=0.5)
            S_DIS thres 0 dis_ctrl 0 SW_DIS
            .TRAN 0.01m 20m UIC
            .MEAS TRAN trig_fall WHEN V(trigger)=2.5 FALL=1
            .MEAS TRAN out_rise WHEN V(out)=2.5 RISE=1
            .MEAS TRAN out_fall WHEN V(out)=2.5 FALL=1
            .MEAS TRAN pw PARAM='out_fall - out_rise'
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var trig_fall = MeasurementValue(result, "trig_fall");
        var out_rise = MeasurementValue(result, "out_rise");
        var out_fall = MeasurementValue(result, "out_fall");
        var pw = MeasurementValue(result, "pw");
        Assert.True(((trig_fall < out_rise)), CaseLabel(result));
        Assert.True(((out_rise < out_fall)), CaseLabel(result));
        AssertMeasurementNear(result, "pw", 0.011, 0.001);
    }

