            Vpwm pwm 0 PULSE(0 5 0 1n 1n 50u 100u)
            R1 pwm filt 10k
            C1 filt 0 0.1u
            E1 out 0 filt out 1e5
            .TRAN 1u 10m 0 1u
            .MEAS TRAN vout_avg AVG V(out) FROM=5m TO=10m
            .MEAS TRAN vout_ripple PP V(out) FROM=5m TO=10m
            .END
