    // Prompt: Three-stage current-starved ring oscillator using PMOS and NMOS transistors
    [Fact]
    public void CMOS_current_starved_ring_oscillator_VCO_b918f0f05c4ff04c()
    {
        var result = RunAcceptedExample(
            "deepseek:01383_5990bbe91453af78:b918f0f05c4ff04c",
            """
            * CMOS current-starved ring oscillator VCO
            VDD vdd 0 DC 5
            Vctrl ctrl 0 DC 2.5
            Rctrl ctrl 0 100k
            Mbp bias_p bias_p vdd vdd pch W=10u L=1u
            Mbn bias_p ctrl 0 0 nch W=5u L=1u
            M2p bias_n bias_p vdd vdd pch W=10u L=1u
            Mbn2 bias_n bias_n 0 0 nch W=5u L=1u
            MP1s sp1 bias_p vdd vdd pch W=10u L=1u
            MP1inv out1 out3 sp1 vdd pch W=5u L=0.5u
            MN1inv out1 out3 sn1 0 nch W=2u L=0.5u
            MN1s sn1 bias_n 0 0 nch W=5u L=1u
            CL1 out1 0 1p
            MP2s sp2 bias_p vdd vdd pch W=10u L=1u
            MP2inv out2 out1 sp2 vdd pch W=5u L=0.5u
            MN2inv out2 out1 sn2 0 nch W=2u L=0.5u
            MN2s sn2 bias_n 0 0 nch W=5u L=1u
            CL2 out2 0 1p
            MP3s sp3 bias_p vdd vdd pch W=10u L=1u
            MP3inv out3 out2 sp3 vdd pch W=5u L=0.5u
            MN3inv out3 out2 sn3 0 nch W=2u L=0.5u
            MN3s sn3 bias_n 0 0 nch W=5u L=1u
            CL3 out3 0 1p
            .MODEL nch NMOS(VTO=1 KP=100u LAMBDA=0.02)
            .MODEL pch PMOS(VTO=-1 KP=50u LAMBDA=0.02)
            .TRAN 1n 200n
            .IC V(out1)=0
            .MEASURE TRAN period TRIG V(out1) VAL=2.5 RISE=2 TARG V(out1) VAL=2.5 RISE=3
            .MEASURE TRAN freq PARAM=1/period
            .MEASURE TRAN vpp PP V(out1) FROM=50n TO=200n
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "period", 2e-08, 6e-08);
        AssertMeasurementBetween(result, "freq", 15000000.0, 50000000.0);
        AssertMeasurementBetween(result, "vpp", 4.5, 5.5);
    }

    // Prompt: Sample-and-hold: switch S1 closes when VSAMPLE pulse is high (0-1\u03bcs), charging CSH to Vin=2.5V; an ideal unity-gain buffer EBUF isolates the hold node.
    [Fact]
    public void SAR_ADC_Sample_Comparator_Front_End_c25b123971c9d024()
    {
        var result = RunAcceptedExample(
            "deepseek:02221_5d6963507e7e813c:c25b123971c9d024",
            """
            * SAR ADC Sample Comparator Front-End
            VIN in 0 DC 2.5
            VSAMPLE sample 0 PULSE(0 5 0 10n 10n 1u 20u)
            S1 in cap sample 0 swmod
            CSH cap 0 10pF
            EBUF hold 0 cap 0 1.0
            ECOMP out 0 hold dac 1e6
            D1 out 5 dmod
            D2 0 out dmod
            Rload out 0 1k
            VDAC dac 0 PWL(0 0 2u 0 12u 5)
            VCLAMP 5 0 DC 5
            B_DIFF diff 0 V=V(hold)-V(dac)
            .MODEL dmod D(IS=1n RS=1)
            .MODEL swmod SW(RON=10 ROFF=100MEG VT=2 VH=0.5)
            .TRAN 0.01u 15u
            .MEASURE TRAN v_held FIND V(hold) AT=1.5u
            .MEASURE TRAN t_cross WHEN V(diff)=0 CROSS=1
            .MEASURE TRAN v_dac_cross FIND V(dac) WHEN V(diff)=0 CROSS=1
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "v_held", 2.5, 0.05);
        AssertMeasurementNear(result, "t_cross", 7e-06, 1e-07);
        AssertMeasurementNear(result, "v_dac_cross", 2.5, 0.1);
    }

