            "deepseek:01183_f3864687b18fa566:c7336bc87c5ef020",
            """
            * ECL OR/NOR Gate with BJT Differential Switch
            .MODEL NPN NPN(BF=100 IS=1e-15 CJC=0.2p CJE=0.2p TF=10p)
            VEE vee 0 DC -5.2
            VREF ref 0 DC -1.3
            VIN in 0 PULSE(-2 -0.5 2n 0.1n 0.1n 5n 10n)
            I_EE e vee DC 1mA
            R_C1 c1 0 800
            R_C2 c2 0 800
            Q1 c1 in e NPN
            Q2 c2 ref e NPN
            Q3 0 c2 out_or NPN
            Q4 0 c1 out_nor NPN
            R_E1 out_or vee 2k
            R_E2 out_nor vee 2k
            .OP
            .DC VIN -2 -0.5 0.005
            .TRAN 1p 10n
            .MEAS DC v_or_high_dc MAX V(out_or)
            .MEAS DC v_or_low_dc MIN V(out_or)
            .MEAS DC v_thresh WHEN V(out_or)=-1.1 CROSS=1
            .MEAS DC v_nor_high_dc MAX V(out_nor)
            .MEAS DC v_nor_low_dc MIN V(out_nor)
            .MEAS TRAN v_or_high AVG V(out_or) FROM=5n TO=6n
            .MEAS TRAN v_or_low AVG V(out_or) FROM=0 TO=1n
            .MEAS TRAN v_or_swing PARAM = {abs(v_or_high - v_or_low)}
            .MEAS TRAN v_nor_high AVG V(out_nor) FROM=0 TO=1n
            .MEAS TRAN v_nor_low AVG V(out_nor) FROM=5n TO=6n
            .MEAS TRAN v_nor_swing PARAM = {abs(v_nor_high - v_nor_low)}
            .MEAS TRAN t_in_cross WHEN V(in)=-1.25 RISE=1
            .MEAS TRAN t_out_or_cross WHEN V(out_or)=-1.1 RISE=1
            .MEAS TRAN t_prop_delay PARAM = {t_out_or_cross - t_in_cross}
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "v_or_swing", 0.5, 1.0);
        AssertMeasurementLess(result, "t_prop_delay", 1e-09);
        AssertMeasurementBetween(result, "v_thresh", (-1.5), (-1.1));
        AssertMeasurementBetween(result, "v_nor_swing", 0.5, 1.0);
    }

