    // Prompt: Design an open-loop boost converter circuit using a MOSFET switch, diode, inductor, capacitor, and load resistor. The input voltage is 5V, and the switching frequency is 100 kHz. Use a pulse source to drive the gate with a duty cycle of approximately 58%. Include SPICE .MEAS statements to compute average output voltage, output voltage ripple, input power, and output power, and estimate efficiency. Provide the full netlist.
    [Fact]
    public void Boost_Converter_Open_Loop_Switching_Model_8dcbedb53ddff0c5()
    {
        var result = RunAcceptedExample(
            "deepseek:02333_3fad16f2a7821ef7:8dcbedb53ddff0c5",
            """
            * Boost Converter Open Loop Switching Model
            VIN vin 0 DC 5
            VGATE g 0 PULSE(0 10 0 1n 1n 5.83u 10u)
            L1 vin drain 50u
            M1 drain g 0 0 nmod
            D1 drain out dmod
            C1 out 0 100u IC=0
            R1 out 0 10
            .MODEL dmod D(IS=1n RS=0.1)
            .MODEL nmod NMOS(VTO=2 KP=0.5 LAMBDA=0.02)
            .TRAN 0 5ms 0 0.1u
            .MEAS TRAN Vout_avg AVG V(out) FROM=4ms TO=5ms
            .MEAS TRAN Vout_ripple PP V(out) FROM=4ms TO=5ms
            .MEAS TRAN Pin AVG V(vin)*I(VIN) FROM=4ms TO=5ms
            .MEAS TRAN Pout AVG V(out)*I(R1) FROM=4ms TO=5ms
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var vout_avg = MeasurementValue(result, "Vout_avg");
        var vout_ripple = MeasurementValue(result, "Vout_ripple");
        var pin = MeasurementValue(result, "Pin");
        var pout = MeasurementValue(result, "Pout");
        var efficiency = (((pin > 0.0)) ? ((pout / pin) * 100.0) : 0.0);
        AssertMeasurementBetween(result, "Vout_avg", 10.0, 13.0);
        AssertMeasurementLess(result, "Vout_ripple", 1.0);
        Assert.True(((efficiency > 60.0)), CaseLabel(result));
    }

