    public void Instrumentation_Amplifier_with_Driven_Reference_Node_1987bc782f52c117()
    {
        var result = RunAcceptedExample(
            "deepseek:01486_2a1d4c0af2e282ec:1987bc782f52c117",
            """
            * Instrumentation Amplifier with Driven Reference Node
            V_inp inp 0 DC 2.505 AC 0.5
            V_inn inn 0 DC 2.495 AC -0.5
            V_ref ref 0 DC 1
            V_pos vcc 0 DC 10
            V_neg vee 0 DC -10
            
            .subckt ideal_opamp inp inn out vcc vee
            E1 out 0 inp inn 1e6
            .ends
            
            X_U1 inp f1 out1 vcc vee ideal_opamp
            X_U2 inn f2 out2 vcc vee ideal_opamp
            X_U3 nplus n1 out3 vcc vee ideal_opamp
            X_U4 ref ref_out ref_out vcc vee ideal_opamp
            Rf1 out1 f1 10k
            Rf2 out2 f2 10k
            Rg f1 f2 1k
            R1 out2 n1 10k
            Rf3 out3 n1 10k
            R3 out1 nplus 10k
            R4 nplus ref_out 10k
            Rload out3 0 100k
            
            .DC V_ref 1 1 1
            .AC DEC 10 1 100k
            
            .MEAS DC vout_dc FIND V(out3) AT=1
            .MEAS DC vref_dc FIND V(ref_out) AT=1
            .MEAS AC out_1k FIND V(out3) AT=1k
            
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "vout_dc", 1.21, 0.02);
        AssertMeasurementNear(result, "vref_dc", 1.0, 0.01);
        AssertMeasurementNear(result, "out_1k", 21.0, 0.3);
    }

    // Prompt: Full Wheatstone bridge with four strain gauges, two in tension and two in compression.
    [Fact]
    public void Strain_gauge_Wheatstone_bridge_with_instrumentation_amplifier_5124222690558934()
    {
        var result = RunAcceptedExample(
            "deepseek:02157_260a4dd63e0c14b0:5124222690558934",
            """
            * Strain-gauge Wheatstone bridge with instrumentation amplifier
            .param R0=350 GF=2
            Vexc vexc 0 DC 5
            Vstrain strain 0 DC 0
            
            * Behavioral resistors for strain gauges
            B1 vexc bridge_p I=V(vexc,bridge_p)/(R0*(1+GF*V(strain)))
            B2 bridge_p 0 I=V(bridge_p)/(R0*(1-GF*V(strain)))
            B3 vexc bridge_n I=V(vexc,bridge_n)/(R0*(1-GF*V(strain)))
            B4 bridge_n 0 I=V(bridge_n)/(R0*(1+GF*V(strain)))
            
            * Large resistors to prevent floating nodes
            Rbig1 bridge_p 0 1G
            Rbig2 bridge_n 0 1G
            
            * Two-op-amp instrumentation amplifier
            E1 out1 0 bridge_p in1 1e6
            E2 out2 0 bridge_n in2 1e6
            Rf1 out1 in1 10k
            Rf2 out2 in2 10k
            Rg in1 in2 500
            
            * Difference amplifier
            E3 out 0 net2 net1 1e6
            R6 out1 net1 1k
            R7 out2 net2 1k
            R8 net1 out 10k
            R9 net2 0 10k
            
            .DC Vstrain 0 0.001 0.00001
            .MEAS DC vout_0strain FIND v(out) AT=0
            .MEAS DC vout_maxstrain FIND v(out) AT=0.001
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "vout_0strain", 0.0, 0.001);
        AssertMeasurementBetween(result, "vout_maxstrain", 4.0, 4.2);
    }

