    {
        var result = RunAcceptedExample(
            "deepseek:01580_3e970399a063b051:32fde824492a11b9",
            """
            * Op-Amp Sample and Hold with Ideal Switch
            VIN in 0 SIN(0 1 1k)
            VCLK ctrl 0 PULSE(0 5 0 1n 1n 49u 100u)
            S1 in cap ctrl 0 smod
            .MODEL smod SW(RON=1 ROFF=1G VT=1 VH=0)
            C1 cap 0 10n
            E1 out 0 cap 0 1
            .tran 0.1u 200u
            .MEAS TRAN vout_hold FIND V(out) AT=70u
            .MEAS TRAN vin_sample FIND V(in) AT=49u
            .MEAS TRAN vout_hold2 FIND V(out) AT=90u
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
