        var vhold2 = MeasurementValue(result, "vout_hold2");
        Assert.True(((Math.Abs((vhold - vref)) < 0.001)), CaseLabel(result));
        Assert.True(((Math.Abs((vhold - vhold2)) < 1e-06)), CaseLabel(result));
    }

