    // Prompt: AC analysis of electret microphone bias and preamplifier
    [Fact]
    public void Electret_Microphone_Bias_and_Preamplifier_67c3cf92e93b5917()
    {
        var result = RunAcceptedExample(
            "deepseek:02175_8b5663990864e956:67c3cf92e93b5917",
            """
            * Electret Microphone Bias and Preamplifier
            Vcc vcc 0 DC 5
            Vmic mic_sig 0 AC 1
            Cmic1 mic_sig mic 10u
            R_bias vcc mic 2.2k
            Rmic mic 0 10k
            Ccouple mic base 10u
            R1 vcc base 100k
            R2 base 0 27k
            Q1 collector base emitter npnmod
            Rc vcc collector 4.7k
            Re emitter 0 1k
            Cout collector out 10u
            Rload out 0 100k
            .model npnmod NPN(IS=1e-15 BF=100)
            .OP
            .AC DEC 10 10 100k
            .MEAS AC gain_db FIND VDB(out)-VDB(mic) AT=1000
            .MEAS AC vout_1k FIND VM(out) AT=1000
            .MEAS AC vout_20 FIND VM(out) AT=20
            .MEAS AC vout_20k FIND VM(out) AT=20000
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "gain_db", 10.0, 20.0);
        AssertMeasurementGreater(result, "vout_1k", 3.0);
        AssertMeasurementRatioBetween(result, "vout_20", "vout_1k", 0.5, 1.5);
        AssertMeasurementRatioBetween(result, "vout_20k", "vout_1k", 0.5, 1.5);
    }

    // Prompt: Design a precision half-wave rectifier using an ideal op-amp and a diode. The input is a 1V 1kHz sine wave. Provide a SPICE netlist with transient analysis and measurements.
