    {
        var result = RunAcceptedExample(
            "deepseek:00712_1ba2b765defed1b8:48eb46e200ab5789",
            """
            * Precision half-wave rectifier using behavioral op-amp
            VIN in 0 SIN(0 1 1k)
            RLOAD out 0 10k
            D1 out_op out dmod
            .MODEL dmod D(IS=1e-12 RS=1)
            E_OP out_op 0 in out 1e6
            .TRAN 1u 5m 0 1u
            .MEAS TRAN vout_peak MAX V(out) FROM=1m TO=5m
            .MEAS TRAN vin_peak MAX V(in) FROM=1m TO=5m
            .MEAS TRAN vout_neg MIN V(out) FROM=2.5m TO=3.5m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        RequireMeasurement(result, "vout_peak");
        RequireMeasurement(result, "vin_peak");
        RequireMeasurement(result, "vout_neg");
        AssertMeasurementNear(result, "vout_peak", 1.0, 0.02);
        AssertMeasurementNear(result, "vin_peak", 1.0, 0.01);
        AssertMeasurementLess(result, "vout_neg", 0.05);
    }

