    // Prompt: 5-stage CMOS current-starved ring oscillator with starved bias currents controlled by VBIASP and VBIASN.
    [Fact]
    public void CMOS_current_starved_ring_oscillator_a1ff97f54e056b90()
    {
        var result = RunAcceptedExample(
            "deepseek:01376_bae3209ef144ef32:a1ff97f54e056b90",
            """
            * CMOS current-starved ring oscillator
            .MODEL NMOS NMOS (VTO=1 KP=50U LAMBDA=0.02)
            .MODEL PMOS PMOS (VTO=-1 KP=20U LAMBDA=0.02)
            VDD VDD 0 DC 5
            VBIASP VBIASP 0 DC 3.8
            VBIASN VBIASN 0 DC 1.4
            * Stage 1
            Mp1s1 VDD VBIASP n1p VDD PMOS W=40U L=2U
            Mp1i1 node2 node1 n1p VDD PMOS W=20U L=2U
            Mn1i1 node2 node1 n1n 0 NMOS W=10U L=2U
            Mn1s1 n1n VBIASN 0 0 NMOS W=4U L=2U
            C1 node2 0 0.1pF
            * Stage 2
            Mp2s2 VDD VBIASP n2p VDD PMOS W=40U L=2U
            Mp2i2 node3 node2 n2p VDD PMOS W=20U L=2U
            Mn2i2 node3 node2 n2n 0 NMOS W=10U L=2U
            Mn2s2 n2n VBIASN 0 0 NMOS W=4U L=2U
            C2 node3 0 0.1pF
            * Stage 3
            Mp3s3 VDD VBIASP n3p VDD PMOS W=40U L=2U
            Mp3i3 node4 node3 n3p VDD PMOS W=20U L=2U
            Mn3i3 node4 node3 n3n 0 NMOS W=10U L=2U
            Mn3s3 n3n VBIASN 0 0 NMOS W=4U L=2U
            C3 node4 0 0.1pF
            * Stage 4
            Mp4s4 VDD VBIASP n4p VDD PMOS W=40U L=2U
            Mp4i4 node5 node4 n4p VDD PMOS W=20U L=2U
            Mn4i4 node5 node4 n4n 0 NMOS W=10U L=2U
            Mn4s4 n4n VBIASN 0 0 NMOS W=4U L=2U
            C4 node5 0 0.1pF
            * Stage 5
            Mp5s5 VDD VBIASP n5p VDD PMOS W=40U L=2U
            Mp5i5 node1 node5 n5p VDD PMOS W=20U L=2U
            Mn5i5 node1 node5 n5n 0 NMOS W=10U L=2U
            Mn5s5 n5n VBIASN 0 0 NMOS W=4U L=2U
            C5 node1 0 0.1pF
            * Output buffer
            Mpout out node1 VDD VDD PMOS W=20U L=2U
            Mnout out node1 0 0 NMOS W=10U L=2U
            Rload out 0 10k
            CL out 0 1pF
            .IC V(node1)=0.1
            .TRAN 0.1n 15u UIC
            .MEAS TRAN period TRIG V(out) VAL=2.5 RISE=2 TARG V(out) VAL=2.5 RISE=3
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var period = MeasurementValue(result, "period");
        Assert.True(((period > 2e-07)), CaseLabel(result));
        Assert.True(((period < 1e-06)), CaseLabel(result));
    }

    // Prompt: The circuit is an NMOS source follower (common-drain) amplifier.
    [Fact]
    public void NMOS_Source_Follower_with_Resistor_Load_9b2b969f2bd8f371()
    {
        var result = RunAcceptedExample(
            "deepseek:00258_d03a311e6fe3c761:9b2b969f2bd8f371",
            """
            NMOS Source Follower with Resistor Load
            VDD vdd 0 DC 12
            Vin gate 0 DC 6 AC 1
            Rload out 0 5k
            M1 vdd gate out out nmos W=62u L=1u
            .model nmos NMOS (VTO=1 KP=50u LAMBDA=0.02)
            .op
            .ac dec 10 1 1MEG
            .dc Vin 0 12 0.1
            .meas AC ac_gain_lf AVG V(out) FROM=1 TO=1.000001
            .meas AC ac_gain_1k AVG V(out) FROM=1k TO=1.000001k
            .meas DC dc_v5p9 AVG V(out) FROM=5.9 TO=5.900001
            .meas DC dc_v6p1 AVG V(out) FROM=6.1 TO=6.100001
            .end
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "ac_gain_lf", 0.9, 0.95);
        AssertMeasurementBetween(result, "ac_gain_1k", 0.9, 0.95);
        var v59 = MeasurementValue(result, "dc_v5p9");
        var v61 = MeasurementValue(result, "dc_v6p1");
        var dc_gain = ((v61 - v59) / 0.2);
        Assert.True((((dc_gain > 0.9)) && ((dc_gain < 0.95))), CaseLabel(result));
    }

