    // Prompt: Thermistor voltage divider with parallel linearization resistor.
    [Fact]
    public void Thermistor_voltage_divider_with_parallel_linearization_35b3a9e37c572f3a()
    {
        var result = RunAcceptedExample(
            "deepseek:02141_d270e762fa2084bd:35b3a9e37c572f3a",
            """
            * Thermistor voltage divider with parallel linearization
            V1 vcc 0 DC 3.3
            R1 vcc out 10k
            Vtemp temp_net 0 DC 25
            Rtherm out 0 R=10k*(1-0.01*(V(temp_net)-25)+0.0001*(V(temp_net)-25)*(V(temp_net)-25))
            Rlin out 0 3k
            .DC Vtemp -20 70 1
            .MEAS DC Vout_neg20 FIND V(out) AT=-20
            .MEAS DC Vout_25 FIND V(out) AT=25
            .MEAS DC Vout_70 FIND V(out) AT=70
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var v_neg20 = MeasurementValue(result, "Vout_neg20");
        var v_25 = MeasurementValue(result, "Vout_25");
        var v_70 = MeasurementValue(result, "Vout_70");
        var v_lin = (v_neg20 + (((25.0 - (-20.0)) * (v_70 - v_neg20)) / (70.0 - (-20.0))));
        var error = Math.Abs((v_25 - v_lin));
        Assert.True(((error < 0.01)), CaseLabel(result));
        Assert.True(((v_neg20 > v_25) && (v_25 > v_70)), CaseLabel(result));
    }

