    {
        var result = RunAcceptedExample(
            "deepseek:01371_a4e5043b297b0f0d:c573c0e02cd46751",
            """
            * CMOS Dynamic Precharge Inverter
            M1 OUT CLK VDD VDD pmos_mod L=1u W=10u
            M2 OUT IN N001 0 nmos_mod L=1u W=4u
            M3 N001 CLK 0 0 nmos_mod L=1u W=4u
            CLOAD OUT 0 20f
            VDD VDD 0 DC 5.0
            VIN IN 0 PULSE(0 5.0 20n 0.5n 0.5n 50n 200n)
            VCLK CLK 0 PULSE(0 5.0 0 0.5n 0.5n 40n 100n)
            .MODEL pmos_mod PMOS(VTO=-0.8 KP=30u LAMBDA=0.05)
            .MODEL nmos_mod NMOS(VTO=0.8 KP=60u LAMBDA=0.05)
            .OP
            .TRAN 0.05n 200n
            .MEAS TRAN vout_precharge AVG V(OUT) FROM=60n TO=70n
            .MEAS TRAN vout_evaluate AVG V(OUT) FROM=30n TO=40n
