    // Prompt: BJT differential pair with an active current mirror tail source using Q3 and Q4
    [Fact]
    public void BJT_Differential_Pair_with_Tail_Current_Source_78618bc6ae9c8b8c()
    {
        var result = RunAcceptedExample(
            "deepseek:00198_7c0c3f90c81e3a46:78618bc6ae9c8b8c",
            """
            * BJT Differential Pair with Tail Current Source
            VCC VCC 0 DC 12
            VEE VEE 0 DC -12
            VIN1 in1 0 DC 0
            VIN2 in2 0 DC 0
            R1 VCC out1 10k
            R2 VCC out2 10k
            R3 VEE e3 100
            R4 VEE e4 100
            R5 VCC n1 20k
            Q3 n1 n1 e3 npn_mod
            Q4 tail n1 e4 npn_mod
            Q1 out1 in1 tail npn_mod
            Q2 out2 in2 tail npn_mod
            .model npn_mod NPN(IS=1e-15 BF=100 VAF=50)
            .op
            .dc VIN1 -0.02 0.02 0.001
            .meas DC VOUTMAX MAX V(out1)
            .meas DC VOUTMIN MIN V(out1)
            .meas DC VOUT0 FIND V(out1) AT=0
            .meas DC VOUT2MAX MAX V(out2)
            .meas DC VOUT2MIN MIN V(out2)
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var VMAX = MeasurementValue(result, "VOUTMAX");
        var VMIN = MeasurementValue(result, "VOUTMIN");
        var V0 = MeasurementValue(result, "VOUT0");
        var gain = ((VMAX - VMIN) / 0.04);
        AssertMeasurementBetween(result, "VOUT0", 5.9, 6.6);
        Assert.True((((gain > 90.0)) && ((gain < 130.0))), CaseLabel(result));
        AssertMeasurementRatioBetween(result, "VOUT2MAX", "VOUTMAX", 0.9, 1.1);
        AssertMeasurementRatioBetween(result, "VOUT2MIN", "VOUTMIN", 0.9, 1.1);
    }

