    // Prompt: Triangle-wave generator built from an integrator and a Schmitt trigger.
    [Fact]
    public void Triangle_wave_oscillator_using_integrator_and_Schmitt_trigger_765928324892f673()
    {
        var result = RunAcceptedExample(
            "deepseek:00398_739944c002f4855d:765928324892f673",
            """
            * Triangle-wave oscillator using integrator and Schmitt trigger
            .OPTIONS ITL1=500 ITL4=100 RELTOL=1e-6
            VCC Vcc 0 DC 15
            VEE Vee 0 DC -15
            
            * Non-inverting Schmitt trigger
            Rin out_int noninv 10k
            Rf out_sch noninv 20k
            E_sch out_sch 0 TABLE { V(noninv) } = (-15,-15) (-0.001,-15) (0.001,15) (15,15)
            
            * Inverting integrator with high-gain op-amp
            Rint out_sch inv_int 10k
            Cint inv_int out_int 0.1u
            E_int out_int 0 0 inv_int 1e6
            
            * Initial condition to start oscillation
            .IC V(out_int)=0.1
            
            * Transient analysis with UIC and tight max step
            .TRAN 0.1u 30m 0 1u UIC
            
            * Measurements: period via two when statements
            .MEAS TRAN t1 WHEN V(out_sch)=0 RISE=1 TD=10m
            .MEAS TRAN t2 WHEN V(out_sch)=0 RISE=2 TD=10m
            .MEAS TRAN period PARAM t2-t1
            
            * Triangle amplitude (peak-to-peak) after startup
            .MEAS TRAN v_tri_pp PP V(out_int) FROM=10m TO=30m
            
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var period = MeasurementValue(result, "period");
        Assert.True((!Equals(period, null)), CaseLabel(result));
        var freq = (1.0 / period);
        Assert.True(((480.0 <= freq) && (freq <= 520.0)), CaseLabel(result));
        AssertMeasurementBetween(result, "v_tri_pp", 14.0, 16.0);
    }

