    // Prompt: Design a Tow-Thomas biquad band-stop filter with a notch at 1 kHz and Q=10.
    [Fact]
    public void Tow_Thomas_biquad_band_stop_filter_9b7b06d950509ffa()
    {
        var result = RunAcceptedExample(
            "deepseek:02467_3d0cf386fc8a72aa:9b7b06d950509ffa",
            """
            * Tow-Thomas biquad band-stop filter
            VIN in 0 DC 0 AC 1
            * Op-amp E3: inverting summer
            R4 in n3 159K
            R5 LP n3 15.9K
            Rf sum_out n3 15.9K
            E3 sum_out 0 0 n3 100K
            * Op-amp E1: lossy integrator (BP output)
            R1 sum_out n1 15.9K
            C1 BP n1 10E-9
            RQ BP n1 159K
            E1 BP 0 0 n1 100K
            * Op-amp E2: integrator (LP output)
            R2 BP n2 15.9K
            C2 LP n2 10E-9
            E2 LP 0 0 n2 100K
            * Op-amp E4: difference amplifier (subtractor) to produce notch
            R6 in n4 10K
            R7 n4 0 10K
            R8 BP n5 10K
            R9 n5 out 10K
            E4 out 0 n4 n5 100K
            * Analysis
            .AC DEC 100 10 100K
            .MEAS AC notch_min MIN VDB(out)
            .MEAS AC f_lower WHEN VDB(out) = -3 CROSS=1
            .MEAS AC f_upper WHEN VDB(out) = -3 CROSS=2
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "notch_min", (-100.0), (-30.0));
        AssertMeasurementBetween(result, "f_lower", 900.0, 1000.0);
        AssertMeasurementBetween(result, "f_upper", 1000.0, 1100.0);
    }

