    // Prompt: Design a BJT phase splitter with equal 10k collector and emitter resistors
    [Fact]
    public void BJT_Phase_Splitter_with_split_collector_and_emitter_loads_92a1201e89c735c5()
    {
        var result = RunAcceptedExample(
            "deepseek:00973_4fdc2dcd91f8782f:92a1201e89c735c5",
            """
            * BJT Phase Splitter with split collector and emitter loads
            VCC vcc 0 DC 12
            VIN in 0 DC 0 AC 1
            R1 vcc base 100k
            R2 base 0 27k
            Cin in base 1uF
            Q1 out_c base out_e npnmod
            RC vcc out_c 10k
            RE out_e 0 10k
            .MODEL npnmod NPN(IS=1e-14 BF=100 VAF=50)
            .OP
            .AC DEC 10 10 1MEG
            .MEAS OP out_c_dc FIND V(out_c) AT=0
            .MEAS OP out_e_dc FIND V(out_e) AT=0
            .MEAS AC out_c_gain MAX VM(out_c)
            .MEAS AC out_e_gain MAX VM(out_e)
            .MEAS AC phase_c FIND VP(out_c) AT=1k
            .MEAS AC phase_e FIND VP(out_e) AT=1k
            .END
            """);

        var PI = 3.141592653589793;
        AssertAllMeasurementsSuccessful(result);
        var out_c_dc = MeasurementValue(result, "out_c_dc");
        var out_e_dc = MeasurementValue(result, "out_e_dc");
        Assert.True(((out_c_dc > out_e_dc)), CaseLabel(result));
        Assert.True(((out_c_dc < 12.0)), CaseLabel(result));
        AssertMeasurementBetween(result, "out_c_gain", 0.8, 1.2);
        AssertMeasurementBetween(result, "out_e_gain", 0.8, 1.2);
        var phase_c = MeasurementValue(result, "phase_c");
        var phase_e = MeasurementValue(result, "phase_e");
        var phase_diff = Math.Abs((phase_c - phase_e));
        Assert.True(((Math.Abs((phase_diff - PI)) < 0.1)), CaseLabel(result));
    }

