            "deepseek:00742_d769bae25ebd3509:c3e5a47a8dc18abe",
            """
            * Diode Peak Detector with Bleed Resistor
            VIN in 0 SIN(0 5 1k 0 0 0)
            D1 in out DMOD
            C1 out 0 1u
            R1 out 0 100k
            .MODEL DMOD D(IS=2.52n RS=0.568 N=1.752 CJO=4p M=0.4 BV=100 TT=5n)
            .TRAN 0.1m 10m
            .MEASURE TRAN Vpeak MAX V(out) FROM=1m TO=10m
            .MEASURE TRAN Vmin MIN V(out) FROM=1m TO=10m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var vpeak = ToDouble(MeasurementValue(result, "Vpeak"));
        var vmin = ToDouble(MeasurementValue(result, "Vmin"));
        Assert.True(((4.0 <= vpeak) && (vpeak <= 5.0)), CaseLabel(result));
        Assert.True(((3.0 <= vmin) && (vmin <= 5.0)), CaseLabel(result));
        Assert.True(((vpeak > vmin)), CaseLabel(result));
        var ripple = (vpeak - vmin);
        Assert.True(((0.0 < ripple) && (ripple < 0.5)), CaseLabel(result));
    }

