    // Prompt: LC band-pass ladder filter synthesized from 3rd-order Butterworth low-pass prototype.
    [Fact]
    public void LC_Band_pass_Ladder_Filter_4ff3af69372bd902()
    {
        var result = RunAcceptedExample(
            "deepseek:00592_41bed9523a06b060:4ff3af69372bd902",
            """
            * LC Band-pass Ladder Filter
            V1 in 0 AC 1
            RS in n1 50
            L1 n1 n2 7.9577mH
            C1 n2 n3 31.831nF
            L2 n3 0 39.79uH
            C2 n3 0 6.3662uF
            L3 n3 n4 7.9577mH
            C3 n4 out 31.831nF
            RL out 0 50
            .AC DEC 200 100 100k
            .MEAS AC max_gain MAX VDB(out)
            .MEAS AC bw_lower WHEN VDB(out)=-9.02 CROSS=1
            .MEAS AC bw_upper WHEN VDB(out)=-9.02 CROSS=2
            .MEAS AC stop_1k FIND VDB(out) AT=1k
            .MEAS AC stop_100k FIND VDB(out) AT=100k
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "max_gain", (-7.0), (-5.0));
        var f_low = MeasurementValue(result, "bw_lower");
        var f_high = MeasurementValue(result, "bw_upper");
        var f_center = Math.Pow((f_low * f_high), 0.5);
        Assert.True(((9500.0 <= f_center) && (f_center <= 10500.0)), CaseLabel(result));
        var bw = (f_high - f_low);
        Assert.True(((500.0 <= bw) && (bw <= 2000.0)), CaseLabel(result));
        AssertMeasurementLess(result, "stop_1k", (-40.0));
        AssertMeasurementLess(result, "stop_100k", (-40.0));
    }

