    // Prompt: CMOS transmission-gate D-latch with clocked pass gates and feedback inverters.
    [Fact]
    public void CMOS_Transmission_Gate_D_Latch_34eb5273095d96e9()
    {
        var result = RunAcceptedExample(
            "deepseek:01367_d74cd0ecb7df43e1:34eb5273095d96e9",
            """
            * CMOS Transmission-Gate D-Latch
            VDD vdd 0 DC 5
            VCLK clk 0 PULSE(0 5 10n 0.1n 0.1n 9.8n 20n)
            VD d 0 PULSE(0 5 25n 0.1n 0.1n 15n 40n)
            Mp1 clkb clk vdd vdd pm W=10u L=1u
            Mn1 clkb clk 0 0 nm W=5u L=1u
            Mtg1_n B clk d 0 nm W=5u L=1u
            Mtg1_p B clkb d vdd pm W=10u L=1u
            Mtg2_n B clkb fb 0 nm W=5u L=1u
            Mtg2_p B clk fb vdd pm W=10u L=1u
            Mp_inv1 Q B vdd vdd pm W=10u L=1u
            Mn_inv1 Q B 0 0 nm W=5u L=1u
            Mp_inv2 fb Q vdd vdd pm W=10u L=1u
            Mn_inv2 fb Q 0 0 nm W=5u L=1u
            CLOAD Q 0 0.1p
            .IC V(B)=5 V(Q)=0 V(fb)=5
            .MODEL nm NMOS (LEVEL=1 VTO=1 KP=100u LAMBDA=0.02)
            .MODEL pm PMOS (LEVEL=1 VTO=-1 KP=50u LAMBDA=0.02)
            .TRAN 0.1n 100n UIC
            .MEAS TRAN t_rise TRIG V(clk) VAL=2.5 RISE=1 TARG V(Q) VAL=2.5 RISE=1
            .MEAS TRAN t_fall TRIG V(clk) VAL=2.5 RISE=2 TARG V(Q) VAL=2.5 FALL=1
            .MEAS TRAN vhold MAX V(Q) FROM=20n TO=30n
            .MEAS TRAN vhold_min MIN V(Q) FROM=20n TO=30n
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementLess(result, "t_rise", 2e-09);
        AssertMeasurementLess(result, "t_fall", 2e-09);
        AssertMeasurementGreater(result, "vhold", 4.5);
        AssertMeasurementGreater(result, "vhold_min", 4.5);
    }

