    // Prompt: 4\u2011bit R\u20112R ladder DAC with ideal voltage\u2011follower op\u2011amp buffer. The R\u20112R network uses 1k\u03a9 (R) and 2k\u03a9 (2R) resistors. Digital inputs are represented by voltage sources: b3 and b1 track VREF (code '1'), b2 and b0 are 0V (code '0'). The ladder is terminated with a 2k\u03a9 resistor to ground at the LSB end. The op\u2011amp buffer (E1) forces V(out) \u2248 V(n3), providing low output impedance. A DC sweep of VREF from 0 to 5V in 0.1V steps verifies the transfer characteristic V(out) = 0.625\xb7VREF for input code 1010.
    [Fact]
    public void _4_bit_R_2R_ladder_DAC_with_op_amp_buffer_f176a728f1c7db7c()
    {
        var result = RunAcceptedExample(
            "deepseek:02179_02fc6ea716fff71a:f176a728f1c7db7c",
            """
            * 4-bit R-2R ladder DAC with op-amp buffer
            VREF vref 0 DC 5
            E_B3 b3 0 vref 0 1
            Vb2 b2 0 DC 0
            E_B1 b1 0 vref 0 1
            Vb0 b0 0 DC 0
            Rsh3 n3 b3 2000
            Rser2 n3 n2 1000
            Rsh2 n2 b2 2000
            Rser3 n2 n1 1000
            Rsh1 n1 b1 2000
            Rser4 n1 n0 1000
            Rsh0 n0 b0 2000
            Rgnd n0 0 2000
            E1 out 0 n3 out 100000
            .OP
            .DC VREF 0 5 0.1
            .MEAS DC vout_at_5v FIND v(out) WHEN v(vref)=5
            .MEAS DC vout_at_2_5v FIND v(out) WHEN v(vref)=2.5
            .MEAS DC vref_for_half FIND v(vref) WHEN v(out)=1.5625
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "vout_at_5v", 3.125, 0.01);
        AssertMeasurementNear(result, "vout_at_2_5v", 1.5625, 0.01);
        AssertMeasurementNear(result, "vref_for_half", 2.5, 0.01);
    }

