    // Prompt: Design a 12V-to-5V current-mode buck converter switching at 100kHz.
    [Fact]
    public void current_mode_buck_converter_6a095dba9953f304()
    {
        var result = RunAcceptedExample(
            "deepseek:01930_288e0618554b694e:6a095dba9953f304",
            """
            * current-mode buck converter
            VIN in 0 DC 12
            VGG gg 0 DC 10
            VCLK clk 0 PULSE(0 5 0 10n 10n 100n 10u)
            VREF ref 0 DC 5
            V_sense sw_sense out DC 0
            H_sense vsense 0 V_sense 1
            S_power in sw_node Q 0 SW_power
            D1 0 sw_node DMOD
            L1 sw_node sw_sense 100uH
            C out 0 100uF
            Rload out 0 5
            E_ea ea_out 0 VALUE = { MIN( MAX( (V(ref) - V(out)) * 1000, 0 ), 2 ) }
            Rcomp ea_out vc 10k
            Ccomp vc 0 10n
            E_comp comp_out 0 VALUE = { IF( V(vsense) > V(vc), 10, 0 ) }
            S_set gg Q clk 0 SW_set
            S_reset Q 0 comp_out 0 SW_reset
            CQ Q 0 1n IC=0
            RQ Q 0 1MEG
            .MODEL SW_set SW(RON=100 ROFF=1MEG VT=2.5 VH=0.1)
            .MODEL SW_reset SW(RON=1 ROFF=1MEG VT=2.5 VH=0.1)
            .MODEL SW_power SW(RON=0.1 ROFF=10MEG VT=2 VH=0.1)
            .MODEL DMOD D(IS=1e-12 RS=0.01)
            .TRAN 0 2m 0 1u UIC
            .IC V(Q)=0 V(out)=0
            .MEAS TRAN avg_out AVG V(out) FROM=1.5m TO=2m
            .MEAS TRAN ripple PP V(out) FROM=1.5m TO=2m
            .MEAS TRAN period TRIG V(clk) VAL=2.5 RISE=1 TARG V(clk) VAL=2.5 RISE=2
            .MEAS TRAN freq PARAM 1/period
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "avg_out", 5.0, 0.5);
        AssertMeasurementLess(result, "ripple", 0.2);
        AssertMeasurementNear(result, "freq", 100000.0, 10000.0);
    }

