            """
            * CMOS Telescopic Cascode Amplifier
            VDD 1 0 DC 2.5
            VSS 2 0 DC -2.5
            * Tail current source
            I1 10 2 DC 500U
            * Input differential pair
            M1 20 in1 10 2 NMOD W=50U L=0.5U
            M2 30 in2 10 2 NMOD W=50U L=0.5U
            * NMOS cascode transistors
            M3 40 5 20 2 NMOD W=50U L=0.5U
            M4 50 5 30 2 NMOD W=50U L=0.5U
            * PMOS current mirror load with cascode
            M5 60 60 1 1 PMOD W=50U L=0.5U
            M6 70 60 1 1 PMOD W=50U L=0.5U
            M7 40 6 60 1 PMOD W=50U L=0.5U
            M8 50 6 70 1 PMOD W=50U L=0.5U
            * Bias voltages
            Vbiasn 5 0 DC 1.02
            Vbiasp 6 0 DC 0.47
            * Input voltage sources
            Vin1 in1 0 DC 0 AC 1
            Vin2 in2 0 DC 0 AC 0
            * Load capacitor
            CL 50 0 1P
            * Models
            .MODEL NMOD NMOS (VTO=0.5 KP=100U LAMBDA=0.02 GAMMA=0)
            .MODEL PMOD PMOS (VTO=-0.7 KP=50U LAMBDA=0.02 GAMMA=0)
            * Analyses
            .OP
            .DC Vin1 -0.1 0.1 0.01
            .AC DEC 10 1 1E9
            * Measurements
