            .MEAS DC vds1_dc FIND V(20,10) AT=0
            .MEAS AC max_gain MAX VDB(50)
            .MEAS AC ugfreq WHEN VDB(50)=0 FALL=1
            .MEAS AC gain_at_1k FIND VDB(50) AT=1k
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
