    // Prompt: Current-starved integrator VCO using E-source op-amp and comparator
    [Fact]
    public void VCO_using_current_starved_integrator_7805d7562e8c5039()
    {
        var result = RunAcceptedExample(
            "deepseek:01861_c7661d58f5140ed0:7805d7562e8c5039",
            """
            * VCO using current-starved integrator
            .param vctrl_val=2
            Vctrl ctrl 0 {vctrl_val}
            Eopamp int_out 0 0 inv_int 100k
            C1 int_out inv_int 100n
            Rleak int_out inv_int 100Meg
            R_curr inv_int v_curr 1k
            E_mult v_curr 0 VALUE={ -V(ctrl) * V(comp_out)/5 }
            Ecomp comp_out 0 VALUE={ 5*tanh(1e5*(V(inv_non)-V(int_out))) }
            R3 comp_out inv_non 10k
            R4 inv_non ref 10k
            Vref ref 0 DC 2.5
            .IC V(int_out)=0 V(comp_out)=5
            .TRAN 0.1u 10m UIC
            .STEP param vctrl_val LIST 1 2 3 4 5
            .MEAS TRAN period TRIG V(int_out) VAL=1 RISE=2 TARG V(int_out) VAL=1 RISE=3
            .MEAS TRAN freq PARAM 1/period
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var freq_1v = MeasurementValue(result, "freq", index: 0);
        var freq_5v = MeasurementValue(result, "freq", index: 4);
        Assert.True(((freq_5v > freq_1v)), CaseLabel(result));
        Assert.True(((500.0 <= freq_1v) && (freq_1v <= 6000.0)), CaseLabel(result));
        Assert.True(((3000.0 <= freq_5v) && (freq_5v <= 8000.0)), CaseLabel(result));
    }

