    // Prompt: Zero-crossing detector using ideal op-amp (E source) with clamping diodes.
    [Fact]
    public void Zero_crossing_detector_fa7cca35daa47f0a()
    {
        var result = RunAcceptedExample(
            "deepseek:01613_b6d59398316b850c:fa7cca35daa47f0a",
            """
            * Zero-crossing detector
            VCC vcc 0 DC 5
            VEE vee 0 DC -5
            VIN in 0 SIN(0 1 1k)
            E_AMP amp_int 0 in 0 1e5
            R1 amp_int out 100
            RLOAD out 0 10k
            D1 out vcc DMOD
            D2 vee out DMOD
            .model DMOD D(IS=1e-12)
            .tran 1u 5m 0 0.1u
            .meas TRAN Vout_avg AVG V(out) FROM=0 TO=5m
            .meas TRAN Vout_max MAX V(out)
            .meas TRAN Vout_min MIN V(out)
            .meas TRAN Vout_high WHEN V(out)=4 RISE=1
            .meas TRAN Vout_low WHEN V(out)=-4 FALL=1
            .meas TRAN t_in0 WHEN V(in)=0 RISE=1
            .meas TRAN t_out0 WHEN V(out)=0 RISE=1
            .meas TRAN delay PARAM t_out0 - t_in0
            .meas TRAN t_rise1 WHEN V(out)=0 RISE=1
            .meas TRAN t_rise2 WHEN V(out)=0 RISE=2
            .meas TRAN period PARAM t_rise2 - t_rise1
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "Vout_avg", 0.0, 0.1);
        AssertMeasurementBetween(result, "Vout_max", 5.0, 6.0);
        AssertMeasurementBetween(result, "Vout_min", (-6.0), (-5.0));
        AssertMeasurementNear(result, "period", 0.001, 0.0001);
        AssertMeasurementLess(result, "delay", 1e-05);
    }

    // Prompt: 4-bit SAR ADC front-end with sample-and-hold and comparator using ideal voltage-controlled switches.
    [Fact]
    public void SAR_ADC_Sample_Comparator_Front_End_f6bf021245fc7f03()
    {
        var result = RunAcceptedExample(
            "deepseek:02223_c05853bab52e46ff:f6bf021245fc7f03",
            """
            * SAR ADC Sample Comparator Front End
            * Samples 1.2V input and compares to DAC output during SAR sequence
            Vin in 0 DC 1.2
            Vref vref 0 DC 2.5
            Vclk clk 0 PULSE(0 5 0 1n 1n 0.5u 1u)
            S1 in sample clk 0 swmod
            .model swmod SW(RON=100 ROFF=1MEG VT=2.5 VH=0.5)
            C1 sample 0 10pF
            Ebuf buf 0 sample 0 1.0
            Rbuf buf comp_pos 1k
            Ecomp comp_out 0 VALUE={( V(comp_pos) > V(dac_out) )? 5 : 0}
            Vb3 b3 0 PULSE(0 5 1u 1n 1n 0.5u 100u)
            Vb2 b2 0 PULSE(0 5 1.5u 1n 1n 3.5u 100u)
            Vb1 b1 0 PULSE(0 5 2u 1n 1n 3u 100u)
            Vb0 b0 0 PULSE(0 5 2.5u 1n 1n 2.5u 100u)
            Einv3 inv_b3 0 VALUE={5 - V(b3)}
            Einv2 inv_b2 0 VALUE={5 - V(b2)}
            Einv1 inv_b1 0 VALUE={5 - V(b1)}
            Einv0 inv_b0 0 VALUE={5 - V(b0)}
            R2r3 dac_out b3_sw 20k
            S3v b3_sw vref b3 0 swmod
            S3g b3_sw 0 inv_b3 0 swmod
            Rseries1 dac_out node2 10k
            R2r2 node2 b2_sw 20k
            S2v b2_sw vref b2 0 swmod
            S2g b2_sw 0 inv_b2 0 swmod
            Rseries2 node2 node3 10k
            R2r1 node3 b1_sw 20k
            S1v b1_sw vref b1 0 swmod
            S1g b1_sw 0 inv_b1 0 swmod
            Rseries3 node3 node4 10k
            R2r0 node4 b0_sw 20k
            S0v b0_sw vref b0 0 swmod
            S0g b0_sw 0 inv_b0 0 swmod
            Rterm node4 0 20k
            .tran 10n 5u 0 10n
            .meas TRAN samp_out FIND V(buf) AT=0.6u
            .meas TRAN comp1 FIND V(comp_out) AT=1.4u
            .meas TRAN comp2 FIND V(comp_out) AT=1.9u
            .meas TRAN comp3 FIND V(comp_out) AT=2.4u
            .meas TRAN comp4 FIND V(comp_out) AT=2.9u
            .end
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "samp_out", 1.2, 0.1);
        AssertMeasurementLess(result, "comp1", 1.0);
        AssertMeasurementGreater(result, "comp2", 4.0);
        AssertMeasurementGreater(result, "comp3", 4.0);
        AssertMeasurementGreater(result, "comp4", 4.0);
    }

