            """
            * Synchronous AM detector with switching demodulator
            .param pi=3.14159
            V_SQ_P pos 0 PULSE(0 5 0 1n 1n 0.5u 1u)
            V_SQ_N neg 0 PULSE(5 0 0 1n 1n 0.5u 1u)
