            .MEAS TRAN vout_rms RMS V(demod_out) FROM=1m TO=2m
            .MEAS TRAN vout_dc AVG V(diff_out) FROM=1m TO=2m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
