    // Prompt: Design a 555-style monostable timer using two comparators and an RS latch built from behavioral sources.
    [Fact]
    public void _555_Style_Monostable_Timer_Using_Behavioral_Comparators_9103a7d630e2596b()
    {
        var result = RunAcceptedExample(
            "deepseek:01818_8e708dd260bf420d:9103a7d630e2596b",
            """
            * 555-Style Monostable Timer Using Behavioral Comparators
            .TRAN 0.1m 20m UIC
            .PRINT TRAN V(Q) V(trigger) V(threshold)
            .OPTIONS NOOPTS
            
            VCC VCC 0 DC 5
            VTRIG trigger 0 PULSE(5 0 1m 1u 1u 100u 20m)
            
            R_TIMING VCC threshold 10k
            C_TIMING threshold 0 1u IC=0
            
            E_TRIG_COMP trig_comp 0 VALUE={5*(V(trigger) < 1.6667)}
            E_THRESH_COMP thresh_comp 0 VALUE={5*(V(threshold) > 3.3333)}
            
            E_SET_CTRL set_ctrl 0 VALUE={5*(V(trig_comp)>2.5)*(V(thresh_comp)<2.5)}
            E_RESET_CTRL reset_ctrl 0 VALUE={V(thresh_comp)}
            
            C_Q Q 0 1n IC=0
            S_SET VCC Q set_ctrl 0 SWMOD
            S_RESET Q 0 reset_ctrl 0 SWMOD
            
            E_DISCH_CTRL disc_ctrl 0 VALUE={5*(V(Q) < 2.5)}
            S_DISCH threshold 0 disc_ctrl 0 SWMOD
            
            .MODEL SWMOD SW(RON=10 ROFF=100MEG VT=2.5 VH=0.1)
            
            .MEAS TRAN t_rise WHEN V(Q)=2.5 RISE=1
            .MEAS TRAN t_fall WHEN V(Q)=2.5 FALL=1
            .MEAS TRAN pulse_width PARAM t_fall - t_rise
            .MEAS TRAN vth_max MAX V(threshold)
            .MEAS TRAN vth_final FIND V(threshold) AT=20m
            
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "t_rise", 0.0009, 0.0015);
        AssertMeasurementBetween(result, "t_fall", 0.011, 0.013);
        AssertMeasurementBetween(result, "pulse_width", 0.01, 0.012);
        AssertMeasurementBetween(result, "vth_max", 3.2, 3.4);
        AssertMeasurementLess(result, "vth_final", 0.1);
    }

