    // Prompt: NMOS differential pair with PMOS current mirror active load, biased by 100 \xb5A ideal sink to -5 V.
    [Fact]
    public void MOSFET_Differential_Pair_with_Active_Load_90205372d7f0ec4a()
    {
        var result = RunAcceptedExample(
            "deepseek:00267_10b20a2685d07b99:90205372d7f0ec4a",
            """
            * MOSFET Differential Pair with Active Load
            M1 drain1 in_p tail vss nch W=10u L=1u
            M2 out cm tail vss nch W=10u L=1u
            M3 drain1 drain1 vdd vdd pch W=20u L=1u
            M4 out drain1 vdd vdd pch W=20u L=1u
            I1 tail vss DC 100u
            VDD vdd 0 DC 5
            VSS vss 0 DC -5
            VCM cm 0 DC 0
            VIN in_p cm DC 0
            .MODEL nch NMOS(VTO=1 KP=100u LAMBDA=0.02)
            .MODEL pch PMOS(VTO=-1 KP=50u LAMBDA=0.02)
            .OP
            .DC VIN -0.5 0.5 0.01
            .MEAS DC vout_at_0 FIND V(out) AT=0
            .MEAS DC gain DERIV V(out) AT=0
            .MEAS DC vout_sat_pos FIND V(out) AT=0.5
            .MEAS DC vout_sat_neg FIND V(out) AT=-0.5
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var gain = MeasurementValue(result, "gain");
        Assert.True((!Equals(gain, null)), CaseLabel(result));
        Assert.True(((Math.Abs(gain) > 100.0)), CaseLabel(result));
        Assert.True(((Math.Abs(gain) < 300.0)), CaseLabel(result));
        var vout0 = MeasurementValue(result, "vout_at_0");
        Assert.True((!Equals(vout0, null)), CaseLabel(result));
        Assert.True(((3.0 < vout0) && (vout0 < 4.5)), CaseLabel(result));
        var vout_sat_pos = MeasurementValue(result, "vout_sat_pos");
        Assert.True((!Equals(vout_sat_pos, null)), CaseLabel(result));
        Assert.True(((vout_sat_pos > 4.0)), CaseLabel(result));
        var vout_sat_neg = MeasurementValue(result, "vout_sat_neg");
        Assert.True((!Equals(vout_sat_neg, null)), CaseLabel(result));
        Assert.True(((vout_sat_neg < 0.5)), CaseLabel(result));
    }

    // Prompt: Window comparator using two high-gain E sources with open\u2011collector\u2011like diode pull\u2011downs.
