            .TRAN 10u 2m
            
            .MEAS TRAN vth_low FIND v(vin) WHEN v(out)=2.5 RISE=1
            .MEAS TRAN vth_high FIND v(vin) WHEN v(out)=2.5 FALL=1
            
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "vth_low", 1.9, 2.1);
        AssertMeasurementBetween(result, "vth_high", 2.9, 3.1);
    }

