    // Prompt: This is a BJT differential pair with an active current mirror load (PNP transistors) and a tail current source formed by an NPN current mirror.
    [Fact]
    public void BJT_Differential_Pair_with_Active_Load_and_Tail_Current_Mirror_No_Resistive_Load_for_High_Gain_26a5806047a0d908()
    {
        var result = RunAcceptedExample(
            "deepseek:00196_4902454c0df7b751:26a5806047a0d908",
            """
            * BJT Differential Pair with Active Load and Tail Current Mirror (No Resistive Load for High Gain)
            VCC vcc 0 DC 12
            VEE vee 0 DC -12
            VIN1 in1 0 DC 0
            VIN2 in2 0 DC 0
            Rref vcc b5 220k
            Q1 n1 in1 e npn_mod
            Q2 out in2 e npn_mod
            Q3 n1 n1 vcc pnp_mod
            Q4 out n1 vcc pnp_mod
            Q5 col_q5 b5 vee npn_mod
            Q6 b5 b5 vee npn_mod
            Vmeas_tail e col_q5 DC 0
            .MODEL npn_mod NPN(IS=1e-14 BF=100 VAF=100)
            .MODEL pnp_mod PNP(IS=1e-14 BF=50 VAF=50)
            .OP
            .DC VIN1 -50m 50m 1m
            .MEAS DC i_tail FIND I(Vmeas_tail) AT=0
            .MEAS DC v_out_op FIND V(out) AT=0
            .MEAS DC gain DERIV V(out) AT=0
            .MEAS DC vout_max MAX V(out)
            .MEAS DC vout_min MIN V(out)
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementNear(result, "i_tail", 0.0001, 2e-05);
        AssertMeasurementBetween(result, "v_out_op", (-12.0), 12.0);
        AssertMeasurementGreater(result, "gain", 1000.0);
        var vout_max = MeasurementValue(result, "vout_max");
        var vout_min = MeasurementValue(result, "vout_min");
        Assert.True((((vout_max - vout_min) > 1.0)), CaseLabel(result));
    }

