    // Prompt: Schmitt-trigger RC relaxation oscillator using a high-gain op-amp (E1) with output clamping
    [Fact]
    public void Schmitt_trigger_RC_relaxation_oscillator_2e0c49cd0a90baae()
    {
        var result = RunAcceptedExample(
            "deepseek:01829_ca5b78fe1c3741d2:2e0c49cd0a90baae",
            """
            * Schmitt-trigger RC relaxation oscillator
            VDD VDD 0 5
            VSS VSS 0 -5
            E1 out 0 VALUE={LIMIT(1e6 * (V(inp) - V(inn)), -5, 5)}
            R1 out inp 10k
            R2 inp 0 10k
            R3 out inn 100k
            C1 inn 0 10nF
            .IC V(inn)=0.01
            .TRAN 0.01m 10ms 0 10u
            .MEAS TRAN t_period TRIG V(out) VAL=0 RISE=1 TARG V(out) VAL=0 RISE=2 FROM=1ms TO=10ms
            .MEAS TRAN freq PARAM 1/t_period
            .MEAS TRAN vout_max MAX V(out) FROM 1ms TO 10ms
            .MEAS TRAN vout_min MIN V(out) FROM 1ms TO 10ms
            .MEAS TRAN vcap_max MAX V(inn) FROM 1ms TO 10ms
            .MEAS TRAN vcap_min MIN V(inn) FROM 1ms TO 10ms
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        var freq = MeasurementValue(result, "freq");
        AssertMeasurementBetween(result, "freq", 400.0, 500.0);
        AssertMeasurementGreater(result, "vout_max", 4.5);
        AssertMeasurementLess(result, "vout_min", (-4.5));
        AssertMeasurementBetween(result, "vcap_max", 2.0, 3.0);
        AssertMeasurementBetween(result, "vcap_min", (-3.0), (-2.0));
    }

