    {
        var result = RunAcceptedExample(
            "deepseek:02229_fd34bd7d9d46ff5a:58f0c51005381b23",
            """
            * First-order sigma-delta modulator
            VIN in 0 DC 0.3
            R1 in inv 10k
            R2 out_dac inv 10k
            C1 out_int inv 0.1u
            Eint out_int 0 0 inv 100k
            Ecomp out_comp_raw 0 out_int 0 1e6
            Vrefp vp 0 DC 1
            Vrefn vn 0 DC -1
            D1 out_comp_raw vp dideal
            D2 vn out_comp_raw dideal
            .model dideal D(VJ=1e-6)
            Vclk clk 0 PULSE(0 5 0 10n 10n 490n 1u)
            S1 out_comp_raw hold_node clk 0 SW1
            .model SW1 SW(RON=1 ROFF=1e12 VT=2.5 VH=0.1)
            Chold hold_node 0 1p
            Ebuf out_buf 0 hold_node 0 1
            Edac out_dac 0 out_buf 0 1
            .TRAN 0.1u 1m
            .MEAS TRAN avg_dac AVG V(out_dac) FROM=0.2m TO=1m
            .MEAS TRAN avg_in AVG V(in) FROM=0.2m TO=1m
            .END
            """);

        AssertAllMeasurementsSuccessful(result);
        AssertMeasurementBetween(result, "avg_dac", (-0.4), (-0.2));
        AssertMeasurementNear(result, "avg_in", 0.3, 0.01);
    }

